+const std = @import("std");
+const llama = @import("llama.zig");
+const c = llama.c;
+
+/// Profile-Guided Optimization for draft model selection
+/// Two-phase approach: generate target tokens first, then test draft
+/// Never loads both models simultaneously (avoids memory freeze)
+
+pub const PGOResult = struct {
+    acceptance_rate: f32,
+    avg_accepted_per_round: f32,
+    total_tokens: u32,
+    total_accepted: u32,
+    rounds: u32,
+};
+
+/// Calibration prompts for profiling
+const calibration_prompts = [_][]const u8{
+    "The capital of France is",
+    "def fibonacci(n):",
+    "In mathematics, 2 + 2 =",
+    "The quick brown fox",
+    "To be or not to be,",
+};
+
+/// Saved target outputs for offline comparison
+const TargetOutput = struct {
+    prompt_idx: usize,
+    tokens: []c.llama_token,
+};
+
+/// Phase 1: Generate reference tokens from target model
+fn generateTargetTokens(
+    allocator: std.mem.Allocator,
+    target_model_path: []const u8,
+    tokens_per_prompt: usize,
+) ![]TargetOutput {
+    std.debug.print("   Phase 1: Generating target reference tokens...\n", .{});
+
+    var target_model = try llama.Model.load(target_model_path, .{
+        .n_gpu_layers = 0, // CPU to avoid memory issues
+        .use_mmap = true,
+    });
+    defer target_model.deinit();
+
+    var target_ctx = try llama.Context.init(&target_model, .{
+        .n_ctx = 512,
+        .n_batch = 64,
+    });
+    defer target_ctx.deinit();
+
+    const vocab = target_model.getVocab();
+
+    // Greedy sampler
+    const sampler = c.llama_sampler_chain_init(c.llama_sampler_chain_default_params());
+    defer c.llama_sampler_free(sampler);
+    c.llama_sampler_chain_add(sampler, c.llama_sampler_init_greedy());
+
+    var outputs = try std.ArrayList(TargetOutput).initCapacity(allocator, calibration_prompts.len);
+
+    for (calibration_prompts, 0..) |prompt, prompt_idx| {
+        // Tokenize
+        var prompt_tokens: [256]c.llama_token = undefined;
+        const n_prompt = c.llama_tokenize(
+            vocab,
+            prompt.ptr,
+            @intCast(prompt.len),
+            &prompt_tokens,
+            @intCast(prompt_tokens.len),
+            true,
+            true,
+        );
+        if (n_prompt < 0) continue;
+
+        const n_prompt_tokens: usize = @intCast(n_prompt);
+
+        // Process prompt
+        var batch = c.llama_batch_init(@intCast(n_prompt_tokens), 0, 1);
+        defer c.llama_batch_free(batch);
+
+        for (0..n_prompt_tokens) |i| {
+            batch.token[i] = prompt_tokens[i];
+            batch.pos[i] = @intCast(i);
+            batch.n_seq_id[i] = 1;
+            batch.seq_id[i][0] = 0;
+            batch.logits[i] = 0;
+        }
+        batch.logits[n_prompt_tokens - 1] = 1;
+        batch.n_tokens = @intCast(n_prompt_tokens);
+
+        if (c.llama_decode(target_ctx.handle, batch) != 0) continue;
+
+        // Generate tokens
+        var generated = try allocator.alloc(c.llama_token, tokens_per_prompt);
+        var pos: usize = n_prompt_tokens;
+        var count: usize = 0;
+
+        while (count < tokens_per_prompt) {
+            const token = c.llama_sampler_sample(sampler, target_ctx.handle, -1);
+            if (c.llama_vocab_is_eog(vocab, token)) break;
+
+            generated[count] = token;
+            count += 1;
+
+            // Feed token back
+            var single = c.llama_batch_init(1, 0, 1);
+            defer c.llama_batch_free(single);
+            single.token[0] = token;
+            single.pos[0] = @intCast(pos);
+            single.n_seq_id[0] = 1;
+            single.seq_id[0][0] = 0;
+            single.logits[0] = 1;
+            single.n_tokens = 1;
+            pos += 1;
+
+            if (c.llama_decode(target_ctx.handle, single) != 0) break;
+        }
+
+        try outputs.append(allocator, .{
+            .prompt_idx = prompt_idx,
+            .tokens = generated[0..count],
+        });
+
+        // Clear KV for next prompt
+        const mem = c.llama_get_memory(target_ctx.handle);
+        c.llama_memory_clear(mem, true);
+    }
+
+    std.debug.print("   Generated {} reference sequences\n", .{outputs.items.len});
+    return try outputs.toOwnedSlice(allocator);
+}
+
+/// Phase 2: Test draft model against saved target tokens
+fn testDraftAcceptance(
+    allocator: std.mem.Allocator,
+    draft_model_path: []const u8,
+    target_outputs: []const TargetOutput,
+    n_gpu_layers: i32,
+) !PGOResult {
+    _ = allocator; // Used for potential future allocations
+    std.debug.print("   Phase 2: Testing draft acceptance...\n", .{});
+
+    var draft_model = try llama.Model.load(draft_model_path, .{
+        .n_gpu_layers = n_gpu_layers,
+        .use_mmap = true,
+    });
+    defer draft_model.deinit();
+
+    var draft_ctx = try llama.Context.init(&draft_model, .{
+        .n_ctx = 512,
+        .n_batch = 64,
+    });
+    defer draft_ctx.deinit();
+
+    const vocab = draft_model.getVocab();
+
+    const sampler = c.llama_sampler_chain_init(c.llama_sampler_chain_default_params());
+    defer c.llama_sampler_free(sampler);
+    c.llama_sampler_chain_add(sampler, c.llama_sampler_init_greedy());
+
+    var total_accepted: u32 = 0;
+    var total_tokens: u32 = 0;
+
+    for (target_outputs) |output| {
+        const prompt = calibration_prompts[output.prompt_idx];
+
+        // Tokenize prompt
+        var prompt_tokens: [256]c.llama_token = undefined;
+        const n_prompt = c.llama_tokenize(
+            vocab,
+            prompt.ptr,
+            @intCast(prompt.len),
+            &prompt_tokens,
+            @intCast(prompt_tokens.len),
+            true,
+            true,
+        );
+        if (n_prompt < 0) continue;
+
+        const n_prompt_tokens: usize = @intCast(n_prompt);
+
+        // Process prompt
+        var batch = c.llama_batch_init(@intCast(n_prompt_tokens), 0, 1);
+        defer c.llama_batch_free(batch);
+
+        for (0..n_prompt_tokens) |i| {
+            batch.token[i] = prompt_tokens[i];
+            batch.pos[i] = @intCast(i);
+            batch.n_seq_id[i] = 1;
+            batch.seq_id[i][0] = 0;
+            batch.logits[i] = 0;
+        }
+        batch.logits[n_prompt_tokens - 1] = 1;
+        batch.n_tokens = @intCast(n_prompt_tokens);
+
+        if (c.llama_decode(draft_ctx.handle, batch) != 0) continue;
+
+        // Compare draft predictions to target tokens
+        var pos: usize = n_prompt_tokens;
+        for (output.tokens) |target_token| {
+            const draft_token = c.llama_sampler_sample(sampler, draft_ctx.handle, -1);
+
+            total_tokens += 1;
+            if (draft_token == target_token) {
+                total_accepted += 1;
+            }
+
+            // Feed the TARGET token (to continue correctly)
+            var single = c.llama_batch_init(1, 0, 1);
+            defer c.llama_batch_free(single);
+            single.token[0] = target_token;
+            single.pos[0] = @intCast(pos);
+            single.n_seq_id[0] = 1;
+            single.seq_id[0][0] = 0;
+            single.logits[0] = 1;
+            single.n_tokens = 1;
+            pos += 1;
+
+            if (c.llama_decode(draft_ctx.handle, single) != 0) break;
+        }
+
+        // Clear KV
+        const mem = c.llama_get_memory(draft_ctx.handle);
+        c.llama_memory_clear(mem, true);
+    }
+
+    const acceptance_rate = if (total_tokens > 0)
+        @as(f32, @floatFromInt(total_accepted)) / @as(f32, @floatFromInt(total_tokens)) * 100.0
+    else
+        0.0;
+
+    return PGOResult{
+        .acceptance_rate = acceptance_rate,
+        .avg_accepted_per_round = acceptance_rate / 100.0 * 8.0, // Assuming depth 8
+        .total_tokens = total_tokens,
+        .total_accepted = total_accepted,
+        .rounds = @intCast(target_outputs.len),
+    };
+}
+
+/// Profile draft model using two-phase approach (never loads both at once)
+/// Uses mmap for target model to minimize memory usage, but will be slow for large models.
+/// For models > 20GB on 16GB RAM, skips full PGO and uses heuristic estimate instead.
+pub fn profileDraftModel(
+    allocator: std.mem.Allocator,
+    target_model_path: []const u8,
+    draft_model_path: []const u8,
+    n_gpu_layers_draft: i32,
+) !PGOResult {
+    // Check target model size
+    const target_file = std.fs.cwd().openFile(target_model_path, .{}) catch |err| {
+        std.debug.print("   ⚠️  Cannot open target model: {}\n", .{err});
+        return err;
+    };
+    defer target_file.close();
+    const target_stat = target_file.stat() catch |err| {
+        std.debug.print("   ⚠️  Cannot stat target model: {}\n", .{err});
+        return err;
+    };
+    const target_size_gb = @as(f32, @floatFromInt(target_stat.size)) / (1024.0 * 1024.0 * 1024.0);
+
+    // Check draft model size
+    const draft_file = std.fs.cwd().openFile(draft_model_path, .{}) catch |err| {
+        std.debug.print("   ⚠️  Cannot open draft model: {}\n", .{err});
+        return err;
+    };
+    defer draft_file.close();
+    const draft_stat = draft_file.stat() catch |err| {
+        std.debug.print("   ⚠️  Cannot stat draft model: {}\n", .{err});
+        return err;
+    };
+    const draft_size_gb = @as(f32, @floatFromInt(draft_stat.size)) / (1024.0 * 1024.0 * 1024.0);
+
+    std.debug.print("\n📊 Running PGO calibration...\n", .{});
+    std.debug.print("   Target: {s} ({d:.1} GB)\n", .{ std.fs.path.basename(target_model_path), target_size_gb });
+    std.debug.print("   Draft: {s} ({d:.1} GB)\n", .{ std.fs.path.basename(draft_model_path), draft_size_gb });
+
+    // For large models, use SSD streaming (mmap) - slow but accurate
+    // This only runs once during build, so speed is acceptable
+    if (target_size_gb > 14.0) {
+        std.debug.print("   ℹ️  Large model - using SSD streaming (this may take a few minutes)\n", .{});
+    }
+
+    const tokens_per_prompt = 30;
+
+    // Phase 1: Generate reference tokens (loads target, then unloads)
+    std.debug.print("   Loading target with mmap (CPU only)...\n", .{});
+    const target_outputs = try generateTargetTokens(allocator, target_model_path, tokens_per_prompt);
+    defer {
+        for (target_outputs) |output| {
+            allocator.free(output.tokens);
+        }
+        allocator.free(target_outputs);
+    }
+
+    // Phase 2: Test draft against reference (loads draft only)
+    const result = try testDraftAcceptance(allocator, draft_model_path, target_outputs, n_gpu_layers_draft);
+
+    std.debug.print("   ✅ Acceptance rate: {d:.1}% ({}/{} tokens)\n", .{
+        result.acceptance_rate,
+        result.total_accepted,
+        result.total_tokens,
+    });
+
+    return result;
+}
+
+/// Test multiple draft configurations and return the best
+pub fn findBestDraftConfig(
+    allocator: std.mem.Allocator,
+    target_model_path: []const u8,
+    draft_candidates: []const []const u8,
+) !struct { path: []const u8, result: PGOResult } {
+    var best_path: []const u8 = "";
+    var best_result = PGOResult{
+        .acceptance_rate = 0,
+        .avg_accepted_per_round = 0,
+        .total_tokens = 0,
+        .total_accepted = 0,
+        .rounds = 0,
+    };
+
+    for (draft_candidates) |candidate| {
+        const result = profileDraftModel(allocator, target_model_path, candidate, 99) catch |err| {
+            std.debug.print("   ⚠️  Failed to profile {s}: {}\n", .{ std.fs.path.basename(candidate), err });
+            continue;
+        };
+
+        if (result.acceptance_rate > best_result.acceptance_rate) {
+            best_result = result;
+            best_path = candidate;
+        }
+    }
+
+    return .{ .path = best_path, .result = best_result };
+}

