+        if (info.type_ != .q6_k) return null;
+        return self.getTensorData(info);
+    }
+
+    // =========================================================================
+    // Generic Quantized Tensor Access (works for any quantization format)
+    // =========================================================================
+
+    /// Get raw bytes for ANY quantized tensor (zero-copy from mmap)
+    /// This works for Q2_K, Q4_K, Q6_K, Q8_0, etc. - any format
+    /// Use this for prefetching when you don't know the quantization format
+    pub fn getRawQuantSlice(self: *Self, name: []const u8) ?[]const u8 {
+        const info = self.getTensor(name) orelse return null;
+        // Check if it's a quantized format (not F32/F16/BF16)
+        const is_quant = switch (info.type_) {
+            .q2_k, .q3_k, .q4_k, .q5_k, .q6_k, .q8_0, .q8_1, .q4_0, .q4_1, .q5_0, .q5_1 => true,
+            else => false,
+        };
+        if (!is_quant) return null;
+        return self.getTensorData(info);
+    }
