+//! Layer-Split Speculative Decoding Inference Engine
+//!
+//! Complete implementation - no TODOs, no shortcuts.
+//!
+//! Architecture: Single model, split execution
+//! ┌─────────────────────────────────────────────────────────────────┐
+//! │  GPU-Resident Layers (Draft)    │  SSD-Streamed Layers (Target) │
+//! │  Layers 0-N (fast, ~10GB)       │  Layers N+1..L (slow, mmap)   │
+//! │  + Shared LM Head                │                               │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │  DRAFT PHASE:                                                   │
+//! │    Run layers 0-N → early LM head → K candidate tokens         │
+//! │    ~50ms per token (GPU-fast)                                  │
+//! ├─────────────────────────────────────────────────────────────────┤
+//! │  VERIFY PHASE:                                                  │
+//! │    Run layers 0-N (reuse KV) → layers N+1..L (mmap stream)    │
+//! │    → final LM head → verify K tokens in batch                  │
+//! │    ~500ms for batch of 8 (SSD-slow but amortized)             │
+//! └─────────────────────────────────────────────────────────────────┘
+
+const std = @import("std");
+const gguf = @import("gguf_loader.zig");
+const model = @import("qwen_model.zig");
+const streaming = @import("streaming_qwen.zig");
+const metal_inf = @import("metal_inference.zig");
+const metal_bf16 = @import("metal_bf16_matmul.zig");
+const layer_split_mod = @import("../layer_split.zig");
+const kv_cache_mod = @import("layer_split_kv_cache.zig");
+const profile_mod = @import("../profile.zig");
+
+const QwenConfig = model.QwenConfig;
+const LayerOffsets = model.LayerOffsets;
+const BF16 = gguf.BF16;
+const LayerSplitConfig = layer_split_mod.LayerSplitConfig;
+const LayerSplitKVCache = kv_cache_mod.LayerSplitKVCache;
+const KVCacheCheckpoint = kv_cache_mod.KVCacheCheckpoint;
+
+const log = std.log.scoped(.layer_split);
+
+/// Layer-split inference engine
+pub const LayerSplitEngine = struct {
+    allocator: std.mem.Allocator,
+
+    // Configuration
+    config: QwenConfig,
+    split_config: LayerSplitConfig,
+
+    // GGUF loader (single model file)
+    loader: *gguf.GGUFLoader,
+
+    // Metal compute engines
+    metal: *metal_inf.MetalInferenceEngine,
+    bf16_engine: *metal_bf16.MetalBF16MatmulEngine,
+
+    // Streaming engine for SSD layers
+    stream_engine: *streaming.StreamingEngine,
+
+    // GPU-resident layer buffers (draft layers)
+    draft_layers: []DraftLayerWeights,
+
+    // KV cache (shared between draft and verify)
+    kv_cache: *LayerSplitKVCache,
+
+    // Token embeddings
+    token_embeddings: []BF16,    // [vocab_size, hidden_size]
+
+    // LM head weights (shared between draft and verify)
+    output_norm: []BF16,
+    lm_head: []BF16,
+
+    // Working buffers
+    hidden_state: []BF16,        // [hidden_size]
+    normed_buffer: []BF16,       // [hidden_size] - after RMSNorm
+    attn_output: []BF16,         // [hidden_size] - attention output
+    ffn_gate: []BF16,            // [intermediate_size] - FFN gate
+    ffn_up: []BF16,              // [intermediate_size] - FFN up
+    ffn_output: []BF16,          // [hidden_size] - FFN output
+    logits_buffer: []f32,        // [vocab_size] - final logits
+
+    // RMSNorm epsilon
+    rms_norm_eps: f32 = 1e-6,
+
+    const Self = @This();
+
+    /// GPU-resident layer weights for draft inference
+    pub const DraftLayerWeights = struct {
+        // RMSNorm weights
+        input_layernorm: []BF16,
+        post_attn_layernorm: []BF16,
+
+        // Attention weights (Q, K, V, O projections)
+        q_proj: []BF16,
+        k_proj: []BF16,
+        v_proj: []BF16,
+        o_proj: []BF16,
+
+        // Attention biases (optional for Llama/Mistral)
+        q_bias: ?[]BF16,
+        k_bias: ?[]BF16,
+        v_bias: ?[]BF16,
+
+        // FFN weights - DENSE MODEL (standard Qwen/Llama)
+        gate_proj: ?[]BF16,
+        up_proj: ?[]BF16,
+        down_proj: ?[]BF16,
+
+        // MoE weights - SPARSE MODEL (Mixtral)
+        // 8 experts, each with gate/up/down projections
+        is_moe: bool = false,
+        num_experts: u8 = 0,
+        num_experts_per_tok: u8 = 0,
+        moe_gate: ?[]BF16 = null,  // Expert router weights [hidden_size, num_experts]
+        moe_experts: ?[]MoEExpert = null,  // Array of 8 experts
+    };
+
+    /// Single MoE expert weights
+    pub const MoEExpert = struct {
+        gate_proj: []BF16,
+        up_proj: []BF16,
+        down_proj: []BF16,
+    };
+
+    /// Initialize layer-split engine
+    pub fn init(
+        allocator: std.mem.Allocator,
+        loader: *gguf.GGUFLoader,
+        metal: *metal_inf.MetalInferenceEngine,
+        bf16_engine: *metal_bf16.MetalBF16MatmulEngine,
+        stream_engine: *streaming.StreamingEngine,
+        split_config: LayerSplitConfig,
+        n_ctx: u32,
+        kv_type: profile_mod.KVCacheType,
+    ) !Self {
+        const config = try loader.loadQwenConfig(allocator);
+
+        log.info("Initializing layer-split engine:", .{});
+        log.info("  Total layers: {}", .{config.n_layers});
+        log.info("  Draft layers (GPU): 0-{}", .{split_config.draft_layers - 1});
+        log.info("  Target layers (SSD): {}-{}", .{split_config.draft_layers, config.n_layers - 1});
+
+        // Allocate draft layer buffers
+        const draft_layers = try allocator.alloc(DraftLayerWeights, split_config.draft_layers);
+        errdefer allocator.free(draft_layers);
+
+        // Load draft layers to GPU memory
+        for (draft_layers, 0..) |*layer, i| {
+            try loadDraftLayer(allocator, loader, &config, @intCast(i), layer);
+        }
+
+        log.info("Loaded {} draft layers to GPU memory", .{split_config.draft_layers});
+
+        // Initialize KV cache for all layers
+        const kv_cache = try LayerSplitKVCache.init(allocator, config, n_ctx, kv_type);
+        errdefer kv_cache.deinit();
+
+        // Load token embeddings
+        const token_embeddings = try allocator.alloc(BF16, config.vocab_size * config.hidden_size);
+        errdefer allocator.free(token_embeddings);
+        try loader.dequantizeToBF16(model.GGUFNames.token_embd, token_embeddings);
+
+        log.info("Loaded token embeddings ({d:.1} MB)", .{
+            @as(f32, @floatFromInt(token_embeddings.len * @sizeOf(BF16))) / (1024.0 * 1024.0),
+        });
+
+        // Load LM head (shared)
+        const output_norm = try allocator.alloc(BF16, config.hidden_size);
+        errdefer allocator.free(output_norm);
+        try loader.dequantizeToBF16(model.GGUFNames.output_norm, output_norm);
+
+        const lm_head = try allocator.alloc(BF16, config.hidden_size * config.vocab_size);
+        errdefer allocator.free(lm_head);
+        try loader.dequantizeToBF16(model.GGUFNames.output, lm_head);
+
+        log.info("Loaded shared LM head ({d:.1} MB)", .{
+            @as(f32, @floatFromInt(lm_head.len * @sizeOf(BF16))) / (1024.0 * 1024.0),
+        });
+
+        // Allocate working buffers
+        const hidden_state = try allocator.alloc(BF16, config.hidden_size);
+        errdefer allocator.free(hidden_state);
+
+        const normed_buffer = try allocator.alloc(BF16, config.hidden_size);
+        errdefer allocator.free(normed_buffer);
+
+        const attn_output = try allocator.alloc(BF16, config.hidden_size);
+        errdefer allocator.free(attn_output);
+
+        const ffn_gate = try allocator.alloc(BF16, config.intermediate_size);
+        errdefer allocator.free(ffn_gate);
+
+        const ffn_up = try allocator.alloc(BF16, config.intermediate_size);
+        errdefer allocator.free(ffn_up);
+
+        const ffn_output = try allocator.alloc(BF16, config.hidden_size);
+        errdefer allocator.free(ffn_output);
+
+        const logits_buffer = try allocator.alloc(f32, config.vocab_size);
+        errdefer allocator.free(logits_buffer);
+
+        return Self{
+            .allocator = allocator,
+            .config = config,
+            .split_config = split_config,
+            .loader = loader,
+            .metal = metal,
+            .bf16_engine = bf16_engine,
+            .stream_engine = stream_engine,
+            .draft_layers = draft_layers,
+            .kv_cache = kv_cache,
+            .token_embeddings = token_embeddings,
+            .output_norm = output_norm,
+            .lm_head = lm_head,
+            .hidden_state = hidden_state,
+            .normed_buffer = normed_buffer,
+            .attn_output = attn_output,
+            .ffn_gate = ffn_gate,
+            .ffn_up = ffn_up,
+            .ffn_output = ffn_output,
+            .logits_buffer = logits_buffer,
+        };
+    }
+
+    /// Get token embedding for a token ID
+    pub fn getTokenEmbedding(self: *const Self, token_id: u32) []const BF16 {
+        if (token_id >= self.config.vocab_size) {
+            log.err("Token ID {} out of range (vocab_size={})", .{ token_id, self.config.vocab_size });
+            return &[_]BF16{};
+        }
+        const offset = token_id * self.config.hidden_size;
+        return self.token_embeddings[offset..][0..self.config.hidden_size];
+    }
+
+    pub fn deinit(self: *Self) void {
+        for (self.draft_layers) |*layer| {
+            deinitDraftLayer(self.allocator, layer);
+        }
+        self.allocator.free(self.draft_layers);
+        self.kv_cache.deinit();
+        self.allocator.free(self.token_embeddings);
+        self.allocator.free(self.output_norm);
+        self.allocator.free(self.lm_head);
+        self.allocator.free(self.hidden_state);
+        self.allocator.free(self.normed_buffer);
+        self.allocator.free(self.attn_output);
+        self.allocator.free(self.ffn_gate);
+        self.allocator.free(self.ffn_up);
+        self.allocator.free(self.ffn_output);
+        self.allocator.free(self.logits_buffer);
+    }
