+
+    /// Restore KV cache to checkpoint (for speculation rejection)
+    pub fn restoreKVCheckpoint(self: *Self, checkpoint: KVCacheCheckpoint) void {
+        kv_cache_mod.restoreCheckpoint(self.kv_cache, checkpoint);
