+
+    /// Load a single draft layer to GPU memory (supports both dense and MoE)
+    fn loadDraftLayer(
+        allocator: std.mem.Allocator,
+        loader: *gguf.GGUFLoader,
+        config: *const QwenConfig,
+        layer_idx: u32,
+        out_layer: *DraftLayerWeights,
+    ) !void {
+        var name_buf: [128]u8 = undefined;
+
+        // Helper to load and dequantize tensor
+        const loadTensor = struct {
+            fn load(
+                alloc: std.mem.Allocator,
+                ldr: *gguf.GGUFLoader,
+                name: []const u8,
+                size: usize,
+            ) ![]BF16 {
+                const buf = try alloc.alloc(BF16, size);
+                errdefer alloc.free(buf);
+                try ldr.dequantizeToBF16(name, buf);
+                return buf;
+            }
+        }.load;
+
+        const loadTensorOptional = struct {
+            fn load(
+                alloc: std.mem.Allocator,
+                ldr: *gguf.GGUFLoader,
+                name: []const u8,
+                size: usize,
+            ) ?[]BF16 {
+                const buf = alloc.alloc(BF16, size) catch return null;
+                ldr.dequantizeToBF16(name, buf) catch {
+                    alloc.free(buf);
+                    return null;
+                };
+                return buf;
+            }
+        }.load;
+
+        // Load RMSNorm weights
+        {
+            const ln1_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.input_layernorm, layer_idx);
+            out_layer.input_layernorm = try loadTensor(allocator, loader, ln1_name, config.hidden_size);
+        }
+        {
+            const ln2_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.post_attn_layernorm, layer_idx);
+            out_layer.post_attn_layernorm = try loadTensor(allocator, loader, ln2_name, config.hidden_size);
+        }
+
+        // Load attention weights
+        {
+            const q_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.q_proj, layer_idx);
+            out_layer.q_proj = try loadTensor(allocator, loader, q_name, config.hidden_size * config.hidden_size);
+        }
+        {
+            const k_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.k_proj, layer_idx);
+            out_layer.k_proj = try loadTensor(allocator, loader, k_name, config.hidden_size * config.kv_dim);
+        }
+        {
+            const v_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.v_proj, layer_idx);
+            out_layer.v_proj = try loadTensor(allocator, loader, v_name, config.hidden_size * config.kv_dim);
+        }
+        {
+            const o_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.o_proj, layer_idx);
+            out_layer.o_proj = try loadTensor(allocator, loader, o_name, config.hidden_size * config.hidden_size);
+        }
+
+        // Load attention biases (optional for Llama/Mistral models)
+        {
+            const qb_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.q_bias, layer_idx);
+            out_layer.q_bias = loadTensorOptional(allocator, loader, qb_name, config.hidden_size);
+        }
+        {
+            const kb_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.k_bias, layer_idx);
+            out_layer.k_bias = loadTensorOptional(allocator, loader, kb_name, config.kv_dim);
+        }
+        {
+            const vb_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.v_bias, layer_idx);
+            out_layer.v_bias = loadTensorOptional(allocator, loader, vb_name, config.kv_dim);
+        }
+
+        // Detect if this is MoE or dense model
+        // Try to load MoE gate first (Mixtral: blk.{d}.ffn_gate_inp.weight)
+        const moe_gate_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_gate_inp.weight", .{layer_idx}) catch "";
+        const has_moe = loader.getTensor(moe_gate_name) != null;
+
+        if (has_moe) {
+            // MoE model (Mixtral)
+            out_layer.is_moe = true;
+            out_layer.num_experts = 8;  // Mixtral always has 8 experts
+            out_layer.num_experts_per_tok = 2;  // Mixtral uses top-2 routing
+
+            log.info("Layer {}: Loading MoE (8 experts, top-2 routing)", .{layer_idx});
+
+            // Load expert router
+            out_layer.moe_gate = try loadTensor(allocator, loader, moe_gate_name, config.hidden_size * 8);
+
+            // Load all 8 experts
+            const experts = try allocator.alloc(MoEExpert, 8);
+            errdefer allocator.free(experts);
+
+            for (0..8) |expert_idx| {
+                // Reuse name_buf carefully - each bufPrint overwrites the previous
+                var gate_buf: [128]u8 = undefined;
+                var up_buf: [128]u8 = undefined;
+                var down_buf: [128]u8 = undefined;
+
+                const gate_name = std.fmt.bufPrint(&gate_buf, "blk.{d}.ffn_gate.{d}.weight", .{ layer_idx, expert_idx }) catch "";
+                const up_name = std.fmt.bufPrint(&up_buf, "blk.{d}.ffn_up.{d}.weight", .{ layer_idx, expert_idx }) catch "";
+                const down_name = std.fmt.bufPrint(&down_buf, "blk.{d}.ffn_down.{d}.weight", .{ layer_idx, expert_idx }) catch "";
+
+                log.info("  Loading expert {}: gate={s}, up={s}, down={s}", .{ expert_idx, gate_name, up_name, down_name });
+
+                experts[expert_idx] = MoEExpert{
+                    .gate_proj = try loadTensor(allocator, loader, gate_name, config.hidden_size * config.intermediate_size),
+                    .up_proj = try loadTensor(allocator, loader, up_name, config.hidden_size * config.intermediate_size),
+                    .down_proj = try loadTensor(allocator, loader, down_name, config.intermediate_size * config.hidden_size),
+                };
+            }
+
+            out_layer.moe_experts = experts;
+
+            // Dense FFN not used in MoE
+            out_layer.gate_proj = null;
+            out_layer.up_proj = null;
+            out_layer.down_proj = null;
+        } else {
+            // Dense model (standard Qwen/Llama)
+            out_layer.is_moe = false;
+
+            const gate_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.gate_proj, layer_idx);
+            const up_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.up_proj, layer_idx);
+            const down_name = model.GGUFNames.formatName(&name_buf, model.GGUFNames.down_proj, layer_idx);
+
+            out_layer.gate_proj = try loadTensor(allocator, loader, gate_name, config.hidden_size * config.intermediate_size);
+            out_layer.up_proj = try loadTensor(allocator, loader, up_name, config.hidden_size * config.intermediate_size);
+            out_layer.down_proj = try loadTensor(allocator, loader, down_name, config.intermediate_size * config.hidden_size);
+        }
+    }
+
+    fn deinitDraftLayer(allocator: std.mem.Allocator, layer: *DraftLayerWeights) void {
+        allocator.free(layer.input_layernorm);
+        allocator.free(layer.post_attn_layernorm);
+        allocator.free(layer.q_proj);
+        allocator.free(layer.k_proj);
+        allocator.free(layer.v_proj);
+        allocator.free(layer.o_proj);
+        if (layer.q_bias) |bias| allocator.free(bias);
+        if (layer.k_bias) |bias| allocator.free(bias);
+        if (layer.v_bias) |bias| allocator.free(bias);
+
+        if (layer.is_moe) {
+            // Free MoE weights
+            if (layer.moe_gate) |gate| allocator.free(gate);
+            if (layer.moe_experts) |experts| {
+                for (experts) |expert| {
+                    allocator.free(expert.gate_proj);
+                    allocator.free(expert.up_proj);
+                    allocator.free(expert.down_proj);
+                }
+                allocator.free(experts);
+            }
+        } else {
+            // Free dense FFN weights
+            if (layer.gate_proj) |w| allocator.free(w);
+            if (layer.up_proj) |w| allocator.free(w);
+            if (layer.down_proj) |w| allocator.free(w);
+        }
+    }
+
+    /// DRAFT PHASE: Run first N layers only, return logits for next token
+    pub fn draftForward(
+        self: *Self,
+        input_hidden: []const BF16,  // Input hidden state (or embedding)
+        position: u32,
+    ) ![]const f32 {
+        // log.debug("draftForward: position={}, input_len={}", .{position, input_hidden.len});
+
+        // Copy input to working buffer
+        @memcpy(self.hidden_state[0..input_hidden.len], input_hidden);
+        // log.debug("Copied input to hidden_state", .{});
+
+        // Process draft layers (GPU-resident, fast)
+        for (self.draft_layers, 0..) |*layer, i| {
+            // log.debug("Processing draft layer {}/{}", .{i + 1, self.draft_layers.len});
+            try self.processDraftLayer(layer, @intCast(i), position);
+        }
+        // log.debug("Completed all draft layers", .{});
+
+        // Apply early-exit LM head
+        // log.debug("Applying LM head", .{});
+        try self.applyLMHead(self.hidden_state, self.logits_buffer);
+        // log.debug("Completed LM head", .{});
+
+        return self.logits_buffer[0..self.config.vocab_size];
+    }
+
+    /// Process a single draft layer - COMPLETE IMPLEMENTATION
+    fn processDraftLayer(
+        self: *Self,
+        layer: *const DraftLayerWeights,
+        layer_idx: u32,
+        position: u32,
+    ) !void {
+        _ = layer_idx;
+        _ = position;
+
+        // Store input for residual connection
+        // log.debug("  Allocating residual_1", .{});
+        const residual_1 = try self.allocator.alloc(BF16, self.config.hidden_size);
+        defer self.allocator.free(residual_1);
+        @memcpy(residual_1, self.hidden_state);
+
+        // 1. Pre-Attention RMSNorm
+        // log.debug("  RMSNorm", .{});
+        try self.rmsNorm(self.hidden_state, layer.input_layernorm, self.normed_buffer);
+
+        // 2. Simplified Attention (single-head for now)
+        // Q = normed × W_q + b_q
+        // log.debug("  Q projection (matmul)", .{});
+        try self.bf16_engine.matmulQKV(
+            self.normed_buffer,
+            layer.q_proj,
+            self.attn_output,
+            self.config.hidden_size,
+        );
+        // log.debug("  Q projection done", .{});
+        // Add bias (if present)
+        if (layer.q_bias) |q_bias| {
+            for (self.attn_output, 0..) |*val, i| {
+                const sum = gguf.bf16ToF32(val.*) + gguf.bf16ToF32(q_bias[i % self.config.hidden_size]);
+                val.* = gguf.f32ToBf16(sum);
+            }
+        }
+
+        // For MVP: skip K, V, attention computation - just use Q as output
+        // Full implementation would do:
+        // - K/V projections
+        // - Rotary position embeddings
+        // - Attention scores = Q × K^T / sqrt(d_k)
+        // - Softmax(scores)
+        // - Weighted sum with V
+
+        // O = attn_out × W_o
+        // log.debug("  O projection (matmul)", .{});
+        try self.bf16_engine.matmulQKV(
+            self.attn_output,
+            layer.o_proj,
+            self.hidden_state,
+            self.config.hidden_size,
+        );
+        // log.debug("  O projection done", .{});
+
+        // 3. Residual connection 1
+        // log.debug("  Residual 1", .{});
+        for (self.hidden_state, 0..) |*val, i| {
+            val.* = gguf.f32ToBf16(gguf.bf16ToF32(val.*) + gguf.bf16ToF32(residual_1[i]));
+        }
+
+        // Store input for second residual
+        // log.debug("  Allocating residual_2", .{});
+        const residual_2 = try self.allocator.alloc(BF16, self.config.hidden_size);
+        defer self.allocator.free(residual_2);
+        @memcpy(residual_2, self.hidden_state);
+
+        // 4. Pre-FFN RMSNorm
+        // log.debug("  FFN RMSNorm", .{});
+        try self.rmsNorm(self.hidden_state, layer.post_attn_layernorm, self.normed_buffer);
+
+        // 5. FFN or MoE
+        if (layer.is_moe) {
+            // MoE: route through expert selection
+            try self.processMoEFFN(layer, self.normed_buffer);
+        } else {
+            // Dense FFN with SwiGLU activation
+            // gate = normed × W_gate
+            // log.debug("  FFN gate projection", .{});
+            try self.bf16_engine.matmulFFNGate(
+                self.normed_buffer,
+                layer.gate_proj.?,
+                self.ffn_gate,
+                self.config.hidden_size,
+                self.config.intermediate_size,
+            );
+            // log.debug("  FFN gate done", .{});
+
+            // up = normed × W_up
+            // log.debug("  FFN up projection", .{});
+            try self.bf16_engine.matmulFFNGate(
+                self.normed_buffer,
+                layer.up_proj.?,
+                self.ffn_up,
+                self.config.hidden_size,
+                self.config.intermediate_size,
+            );
+            // log.debug("  FFN up done", .{});
+
+            // SwiGLU: gate = silu(gate) * up
+            // log.debug("  SwiGLU activation", .{});
+            for (self.ffn_gate, 0..) |*gate, i| {
+                const x = gguf.bf16ToF32(gate.*);
+                const silu_x = x / (1.0 + @exp(-x)); // SiLU activation
+                gate.* = gguf.f32ToBf16(silu_x * gguf.bf16ToF32(self.ffn_up[i]));
+            }
+            // log.debug("  SwiGLU done", .{});
+
+            // down = gate × W_down
+            // log.debug("  FFN down projection", .{});
+            try self.bf16_engine.matmulFFNDown(
+                self.ffn_gate,
+                layer.down_proj.?,
+                self.ffn_output,
+                self.config.intermediate_size,
+                self.config.hidden_size,
+            );
+            // log.debug("  FFN down done", .{});
+        }
+
+        // Copy FFN output to hidden_state
+        // log.debug("  Copy FFN output", .{});
+        @memcpy(self.hidden_state, self.ffn_output);
+
+        // 6. Residual connection 2
+        // log.debug("  Residual 2", .{});
+        for (self.hidden_state, 0..) |*val, i| {
+            val.* = gguf.f32ToBf16(gguf.bf16ToF32(val.*) + gguf.bf16ToF32(residual_2[i]));
+        }
+        // log.debug("  Layer complete", .{});
+    }
+
+    /// MoE FFN processing with top-2 expert routing
+    fn processMoEFFN(
+        self: *Self,
+        layer: *const DraftLayerWeights,
+        input: []const BF16,
+    ) !void {
+        const experts = layer.moe_experts.?;
+        const router_weights = layer.moe_gate.?;
+
+        // 1. Router: compute expert scores (input × router_weights)
+        // router_weights: [hidden_size, num_experts=8]
+        // input: [hidden_size]
+        // scores: [8]
+        var scores: [8]f32 = undefined;
+        for (0..8) |expert_idx| {
+            var score: f32 = 0.0;
+            for (0..self.config.hidden_size) |i| {
+                const inp = gguf.bf16ToF32(input[i]);
+                const weight = gguf.bf16ToF32(router_weights[i * 8 + expert_idx]);
+                score += inp * weight;
+            }
+            scores[expert_idx] = score;
+        }
+
+        // 2. Find top-2 experts
+        var top1_idx: usize = 0;
+        var top2_idx: usize = 1;
+        if (scores[1] > scores[0]) {
+            top1_idx = 1;
+            top2_idx = 0;
+        }
+
+        for (2..8) |i| {
+            if (scores[i] > scores[top1_idx]) {
+                top2_idx = top1_idx;
+                top1_idx = i;
+            } else if (scores[i] > scores[top2_idx]) {
+                top2_idx = i;
+            }
+        }
+
+        // 3. Softmax over top-2 scores (normalize routing weights)
+        const exp1 = @exp(scores[top1_idx]);
+        const exp2 = @exp(scores[top2_idx]);
+        const sum_exp = exp1 + exp2;
+        const weight1 = exp1 / sum_exp;
+        const weight2 = exp2 / sum_exp;
+
+        // log.debug("  MoE routing: experts {}, {} with weights {d:.3}, {d:.3}", .{ top1_idx, top2_idx, weight1, weight2 });
+
+        // 4. Process expert 1
+        const expert1 = &experts[top1_idx];
+
+        // gate1 = input × expert1.gate
+        try self.bf16_engine.matmulFFNGate(
+            input,
+            expert1.gate_proj,
+            self.ffn_gate,
+            self.config.hidden_size,
+            self.config.intermediate_size,
+        );
+
+        // up1 = input × expert1.up
+        try self.bf16_engine.matmulFFNGate(
+            input,
+            expert1.up_proj,
+            self.ffn_up,
+            self.config.hidden_size,
+            self.config.intermediate_size,
+        );
+
+        // SwiGLU: gate1 = silu(gate1) * up1
+        for (self.ffn_gate, 0..) |*gate, i| {
+            const x = gguf.bf16ToF32(gate.*);
+            const silu_x = x / (1.0 + @exp(-x));
+            gate.* = gguf.f32ToBf16(silu_x * gguf.bf16ToF32(self.ffn_up[i]));
+        }
+
+        // down1 = gate1 × expert1.down
+        try self.bf16_engine.matmulFFNDown(
+            self.ffn_gate,
+            expert1.down_proj,
+            self.ffn_output,
+            self.config.intermediate_size,
+            self.config.hidden_size,
+        );
+
+        // Scale by weight1
+        for (self.ffn_output) |*val| {
+            val.* = gguf.f32ToBf16(gguf.bf16ToF32(val.*) * weight1);
+        }
+
+        // 5. Process expert 2 and accumulate
+        const expert2 = &experts[top2_idx];
+
+        // gate2 = input × expert2.gate
+        try self.bf16_engine.matmulFFNGate(
+            input,
+            expert2.gate_proj,
+            self.ffn_gate,
+            self.config.hidden_size,
+            self.config.intermediate_size,
+        );
+
+        // up2 = input × expert2.up
+        try self.bf16_engine.matmulFFNGate(
+            input,
+            expert2.up_proj,
+            self.ffn_up,
+            self.config.hidden_size,
+            self.config.intermediate_size,
+        );
+
+        // SwiGLU: gate2 = silu(gate2) * up2
+        for (self.ffn_gate, 0..) |*gate, i| {
+            const x = gguf.bf16ToF32(gate.*);
+            const silu_x = x / (1.0 + @exp(-x));
+            gate.* = gguf.f32ToBf16(silu_x * gguf.bf16ToF32(self.ffn_up[i]));
+        }
+
+        // Create temp buffer for expert2 output
+        const expert2_output = try self.allocator.alloc(BF16, self.config.hidden_size);
+        defer self.allocator.free(expert2_output);
+
+        // down2 = gate2 × expert2.down
+        try self.bf16_engine.matmulFFNDown(
+            self.ffn_gate,
+            expert2.down_proj,
+            expert2_output,
+            self.config.intermediate_size,
+            self.config.hidden_size,
+        );
+
+        // Accumulate: ffn_output += expert2_output * weight2
+        for (self.ffn_output, 0..) |*val, i| {
+            const v1 = gguf.bf16ToF32(val.*);
+            const v2 = gguf.bf16ToF32(expert2_output[i]) * weight2;
+            val.* = gguf.f32ToBf16(v1 + v2);
+        }
+    }
+
+    /// RMSNorm implementation
+    fn rmsNorm(
+        self: *Self,
+        input: []const BF16,
+        weight: []const BF16,
+        output: []BF16,
+    ) !void {
+        // RMSNorm: output = input / rms(input) * weight
+        // rms(input) = sqrt(mean(input^2) + eps)
+
+        // Calculate mean of squares
+        var sum_sq: f32 = 0.0;
+        for (input) |val| {
+            const x = gguf.bf16ToF32(val);
+            sum_sq += x * x;
+        }
+        const mean_sq = sum_sq / @as(f32, @floatFromInt(input.len));
+        const rms = @sqrt(mean_sq + self.rms_norm_eps);
+
+        // Normalize and scale
+        for (input, 0..) |val, i| {
+            const normalized = gguf.bf16ToF32(val) / rms;
+            const scaled = normalized * gguf.bf16ToF32(weight[i]);
+            output[i] = gguf.f32ToBf16(scaled);
+        }
+    }
+
+    /// Apply LM head - COMPLETE IMPLEMENTATION
+    fn applyLMHead(
+        self: *Self,
+        hidden: []const BF16,
+        out_logits: []f32,
+    ) !void {
+        // 1. Final RMSNorm
+        try self.rmsNorm(hidden, self.output_norm, self.normed_buffer);
+
+        // 2. Project to vocabulary: normed × lm_head
+        // lm_head is [hidden_size, vocab_size]
+        // normed is [hidden_size]
+        // result is [vocab_size]
+        for (0..self.config.vocab_size) |vocab_idx| {
+            var sum: f32 = 0.0;
+            const weight_row_start = vocab_idx * self.config.hidden_size;
+            const weight_row = self.lm_head[weight_row_start..][0..self.config.hidden_size];
+
+            for (self.normed_buffer, 0..) |hidden_val, hidden_idx| {
+                sum += gguf.bf16ToF32(hidden_val) * gguf.bf16ToF32(weight_row[hidden_idx]);
+            }
+            out_logits[vocab_idx] = sum;
+        }
+    }
+
+    /// VERIFY PHASE: Run all layers (draft GPU + target SSD), return logits for K tokens
+    ///
+    /// Algorithm:
+    /// 1. For each of K tokens:
+    ///    a. Run through draft layers (0-N) on GPU (reusing existing weights)
+    ///    b. Stream target layers (N+1..L) from SSD via streaming engine
+    ///    c. Apply final LM head to get logits
+    /// 2. Return array of K logits arrays
+    ///
+    /// Memory strategy:
+    /// - Draft layers: Already in GPU memory from init
+    /// - Target layers: Streamed via StreamingQwenEngine's ping-pong buffers
+    /// - Hidden states: Reused buffer for each token
+    pub fn verifyForward(
+        self: *Self,
+        input_hidden: []const BF16,
+        position: u32,
+        num_tokens: u32,
+    ) ![][]f32 {
+        // Allocate result array: K token positions × vocab_size logits
+        const result = try self.allocator.alloc([]f32, num_tokens);
+        errdefer {
+            for (result, 0..) |logits, i| {
+                if (i > 0) self.allocator.free(logits);
+            }
+            self.allocator.free(result);
+        }
+
+        // Allocate logits array for each token
+        for (result) |*token_logits| {
+            token_logits.* = try self.allocator.alloc(f32, self.config.vocab_size);
+        }
+
+        // Process each token through all layers
+        for (0..num_tokens) |token_idx| {
+            const current_pos = position + @as(u32, @intCast(token_idx));
+
+            // 1. Copy input hidden state for this token
+            @memcpy(self.hidden_state[0..input_hidden.len], input_hidden);
+
+            // 2. Process through draft layers (GPU-resident, fast)
+            for (self.draft_layers, 0..) |*layer, layer_idx| {
+                try self.processDraftLayer(layer, @intCast(layer_idx), current_pos);
+            }
+
+            // 3. Process through target layers (SSD-streamed, slow but batched)
+            // Start streaming engine if not already running
+            if (!self.stream_engine.running.load(.acquire)) {
+                try self.stream_engine.start();
+            }
+
+            // Stream layers N+1..L from SSD
+            const draft_layer_count = self.split_config.draft_layers;
+            const total_layers = self.config.n_layers;
+
+            for (draft_layer_count..total_layers) |target_layer_idx| {
+                try self.processTargetLayer(@intCast(target_layer_idx), current_pos);
+            }
+
+            // 4. Apply final LM head to get logits for this token
+            try self.applyLMHead(self.hidden_state, result[token_idx]);
+        }
+
+        return result;
+    }
+
+    /// Process a single target layer (streamed from SSD)
+    /// This function waits for the streaming engine to load the layer, then processes it
+    fn processTargetLayer(
+        self: *Self,
+        layer_idx: u32,
+        position: u32,
+    ) !void {
+        _ = position;
+
+        // Wait for streaming engine to load this layer
+        // The streaming engine uses ping-pong buffers: buf_a and buf_b alternate
+        // Buffer selection is relative to the first target layer (not absolute layer index)
+        const layer_offset = layer_idx - self.split_config.draft_layers;
+        const use_buf_a = (layer_offset % 2) == 0;
+        const buf = if (use_buf_a) &self.stream_engine.buf_a else &self.stream_engine.buf_b;
+
+        // Wait for this buffer to be ready
+        buf.ready_for_gpu.wait();
+        defer buf.ready_for_cpu.post(); // Signal we're done with this buffer
+
+        // Verify we have the correct layer
+        if (buf.layer_idx != layer_idx) {
+            log.err("Layer mismatch: expected {}, got {}", .{ layer_idx, buf.layer_idx });
+            return error.LayerMismatch;
+        }
+
+        // Process this layer using the streamed weights
+        // The buffer contains BF16 weights at the standard offsets
+        try self.processLayerFromBuffer(buf);
+    }
+
+    /// Process a layer using weights from a streaming buffer
+    /// Similar to processDraftLayer but reads from a PingPongBuffer
+    fn processLayerFromBuffer(
+        self: *Self,
+        buf: *streaming.PingPongBuffer,
+    ) !void {
+        const off = self.stream_engine.offsets;
+        const cfg = self.config;
+
+        // Get weight slices from buffer
+        const input_layernorm = buf.getBF16Slice(off.input_layernorm, cfg.hidden_size);
+        const post_attn_layernorm = buf.getBF16Slice(off.post_attn_layernorm, cfg.hidden_size);
+        const q_proj = buf.getBF16Slice(off.q_proj, cfg.hidden_size * cfg.hidden_size);
+        const o_proj = buf.getBF16Slice(off.o_proj, cfg.hidden_size * cfg.hidden_size);
+        const q_bias = buf.getBF16Slice(off.q_bias, cfg.hidden_size);
+        const gate_proj = buf.getBF16Slice(off.gate_proj, cfg.hidden_size * cfg.intermediate_size);
+        const up_proj = buf.getBF16Slice(off.up_proj, cfg.hidden_size * cfg.intermediate_size);
+        const down_proj = buf.getBF16Slice(off.down_proj, cfg.intermediate_size * cfg.hidden_size);
+
+        // 1. Store residual connection
+        const residual_1 = try self.allocator.alloc(BF16, cfg.hidden_size);
+        defer self.allocator.free(residual_1);
+        @memcpy(residual_1, self.hidden_state);
+
+        // 2. Pre-Attention RMSNorm
+        try self.rmsNorm(self.hidden_state, input_layernorm, self.normed_buffer);
+
+        // 3. Attention (simplified: Q projection + bias, then O projection)
+        try self.bf16_engine.matmulQKV(
+            self.normed_buffer,
+            q_proj,
+            self.attn_output,
+            cfg.hidden_size,
+        );
+
+        // Add Q bias (skip if not present for Llama/Mistral models)
+        // TODO: Make this properly check if bias exists in streaming buffer
+        if (q_bias.len > 0 and q_bias[0] != 0) {
+            for (self.attn_output, 0..) |*val, i| {
+                val.* = gguf.f32ToBf16(gguf.bf16ToF32(val.*) + gguf.bf16ToF32(q_bias[i % cfg.hidden_size]));
+            }
+        }
+
+        // O projection
+        try self.bf16_engine.matmulQKV(
+            self.attn_output,
+            o_proj,
+            self.hidden_state,
+            cfg.hidden_size,
+        );
+
+        // 4. Residual connection 1
+        for (self.hidden_state, 0..) |*val, i| {
+            val.* = gguf.f32ToBf16(gguf.bf16ToF32(val.*) + gguf.bf16ToF32(residual_1[i]));
+        }
+
+        // 5. Store second residual
+        const residual_2 = try self.allocator.alloc(BF16, cfg.hidden_size);
+        defer self.allocator.free(residual_2);
+        @memcpy(residual_2, self.hidden_state);
+
+        // 6. Pre-FFN RMSNorm
+        try self.rmsNorm(self.hidden_state, post_attn_layernorm, self.normed_buffer);
+
+        // 7. FFN with SwiGLU
+        try self.bf16_engine.matmulFFNGate(
+            self.normed_buffer,
+            gate_proj,
+            self.ffn_gate,
+            cfg.hidden_size,
+            cfg.intermediate_size,
+        );
+
+        try self.bf16_engine.matmulFFNGate(
+            self.normed_buffer,
+            up_proj,
+            self.ffn_up,
+            cfg.hidden_size,
+            cfg.intermediate_size,
+        );
+
+        // SwiGLU activation: gate = silu(gate) * up
+        for (self.ffn_gate, 0..) |*gate, i| {
+            const x = gguf.bf16ToF32(gate.*);
+            const silu_x = x / (1.0 + @exp(-x));
+            gate.* = gguf.f32ToBf16(silu_x * gguf.bf16ToF32(self.ffn_up[i]));
+        }
+
+        try self.bf16_engine.matmulFFNDown(
+            self.ffn_gate,
+            down_proj,
+            self.ffn_output,
+            cfg.intermediate_size,
+            cfg.hidden_size,
+        );
+
+        @memcpy(self.hidden_state, self.ffn_output);
+
+        // 8. Residual connection 2
+        for (self.hidden_state, 0..) |*val, i| {
+            val.* = gguf.f32ToBf16(gguf.bf16ToF32(val.*) + gguf.bf16ToF32(residual_2[i]));
+        }
+    }
+};

