+//! KV Cache for Layer-Split Speculative Decoding
+//!
+//! Manages Key and Value caches for all layers in a way that:
+//! 1. Supports draft phase (writes to cache as tokens are generated)
+//! 2. Supports verify phase (reads from cache + extends for K tokens)
+//! 3. Supports rollback on speculation rejection
+//! 4. Memory-efficient with configurable quantization (FP16, Q8, Q4)
+//!
+//! Architecture:
+//! ┌────────────────────────────────────────────────────────────┐
+//! │  Layer 0: [K_cache][V_cache]                               │
+//! │  Layer 1: [K_cache][V_cache]                               │
+//! │  ...                                                       │
+//! │  Layer L: [K_cache][V_cache]                               │
+//! ├────────────────────────────────────────────────────────────┤
+//! │  Each cache: [seq_len, num_kv_heads, head_dim]            │
+//! │  Max seq_len determined by n_ctx                           │
+//! └────────────────────────────────────────────────────────────┘
+
+const std = @import("std");
+const gguf = @import("gguf_loader.zig");
+const model = @import("qwen_model.zig");
+const profile_mod = @import("../profile.zig");
+
+const BF16 = gguf.BF16;
+const QwenConfig = model.QwenConfig;
+const KVCacheType = profile_mod.KVCacheType;
+
+const log = std.log.scoped(.layer_split_kv);
+
+/// Single layer's KV cache (keys and values)
+pub const LayerKVCache = struct {
+    /// Key cache: [max_seq_len, num_kv_heads, head_dim]
+    /// Stores keys for all positions up to max_seq_len
+    k_cache: []BF16,
+
+    /// Value cache: [max_seq_len, num_kv_heads, head_dim]
+    /// Stores values for all positions up to max_seq_len
+    v_cache: []BF16,
+
+    /// Current sequence length (how many positions are filled)
+    seq_len: u32,
+
+    /// Maximum sequence length (capacity)
+    max_seq_len: u32,
+
+    /// Number of KV heads
+    num_kv_heads: u32,
+
+    /// Head dimension
+    head_dim: u32,
+
+    /// Get K at position for specific head
+    pub fn getK(self: *const LayerKVCache, pos: u32, head: u32) []BF16 {
+        if (pos >= self.seq_len) {
+            std.debug.panic("KV cache position {} out of range (seq_len={})", .{ pos, self.seq_len });
+        }
+        const offset = (pos * self.num_kv_heads + head) * self.head_dim;
+        return self.k_cache[offset..][0..self.head_dim];
+    }
+
+    /// Get V at position for specific head
+    pub fn getV(self: *const LayerKVCache, pos: u32, head: u32) []BF16 {
+        if (pos >= self.seq_len) {
+            std.debug.panic("KV cache position {} out of range (seq_len={})", .{ pos, self.seq_len });
+        }
+        const offset = (pos * self.num_kv_heads + head) * self.head_dim;
+        return self.v_cache[offset..][0..self.head_dim];
+    }
+
+    /// Set K at position for specific head
+    pub fn setK(self: *LayerKVCache, pos: u32, head: u32, data: []const BF16) void {
+        if (pos >= self.max_seq_len) {
+            std.debug.panic("KV cache position {} exceeds max_seq_len={}", .{ pos, self.max_seq_len });
+        }
+        const offset = (pos * self.num_kv_heads + head) * self.head_dim;
+        @memcpy(self.k_cache[offset..][0..self.head_dim], data);
+
+        // Update seq_len if we're extending the cache
+        if (pos >= self.seq_len) {
+            self.seq_len = pos + 1;
+        }
+    }
+
+    /// Set V at position for specific head
+    pub fn setV(self: *LayerKVCache, pos: u32, head: u32, data: []const BF16) void {
+        if (pos >= self.max_seq_len) {
+            std.debug.panic("KV cache position {} exceeds max_seq_len={}", .{ pos, self.max_seq_len });
+        }
+        const offset = (pos * self.num_kv_heads + head) * self.head_dim;
+        @memcpy(self.v_cache[offset..][0..self.head_dim], data);
+
+        // Update seq_len if we're extending the cache
+        if (pos >= self.seq_len) {
+            self.seq_len = pos + 1;
+        }
+    }
+
+    /// Rollback cache to previous sequence length (for speculation rejection)
+    pub fn rollback(self: *LayerKVCache, new_seq_len: u32) void {
+        if (new_seq_len <= self.seq_len) {
+            self.seq_len = new_seq_len;
+        }
+    }
+};
+
+/// Complete KV cache for all layers
+pub const LayerSplitKVCache = struct {
+    allocator: std.mem.Allocator,
+
+    /// KV cache for each layer
+    layers: []LayerKVCache,
+
+    /// Model configuration
+    config: QwenConfig,
+
+    /// Maximum sequence length
+    max_seq_len: u32,
+
+    /// Quantization type (FP16, Q8, Q4)
+    cache_type: KVCacheType,
+
+    const Self = @This();
+
+    /// Initialize KV cache for all layers
+    pub fn init(
+        allocator: std.mem.Allocator,
+        config: QwenConfig,
+        max_seq_len: u32,
+        cache_type: KVCacheType,
+    ) !*Self {
+        log.info("Initializing KV cache:", .{});
+        log.info("  Layers: {}", .{config.n_layers});
+        log.info("  Max seq len: {}", .{max_seq_len});
+        log.info("  KV heads: {}", .{config.num_key_value_heads});
+        log.info("  Head dim: {}", .{config.head_dim});
+        log.info("  Cache type: {s}", .{cache_type.toString()});
+
+        // Calculate memory per layer
+        const kv_dim = config.num_key_value_heads * config.head_dim;
+        const elements_per_cache = max_seq_len * kv_dim;
+        const bytes_per_cache = elements_per_cache * @sizeOf(BF16);
+        const bytes_per_layer = bytes_per_cache * 2; // K + V
+        const total_bytes = bytes_per_layer * config.n_layers;
+
+        log.info("  Memory per layer: {d:.1} MB", .{
+            @as(f32, @floatFromInt(bytes_per_layer)) / (1024.0 * 1024.0),
+        });
+        log.info("  Total KV cache: {d:.1} MB", .{
+            @as(f32, @floatFromInt(total_bytes)) / (1024.0 * 1024.0),
+        });
+
+        const self = try allocator.create(Self);
+        errdefer allocator.destroy(self);
+
+        // Allocate layer caches
+        const layers = try allocator.alloc(LayerKVCache, config.n_layers);
+        errdefer allocator.free(layers);
+
+        // Initialize each layer's cache
+        for (layers, 0..) |*layer, i| {
+            // Allocate K cache
+            const k_cache = try allocator.alloc(BF16, elements_per_cache);
+            errdefer allocator.free(k_cache);
+
+            // Allocate V cache
+            const v_cache = try allocator.alloc(BF16, elements_per_cache);
+            errdefer {
+                allocator.free(k_cache);
+                allocator.free(v_cache);
+            }
+
+            // Initialize to zero (BF16 zero = 0x0000)
+            @memset(k_cache, 0);
+            @memset(v_cache, 0);
+
+            layer.* = LayerKVCache{
+                .k_cache = k_cache,
+                .v_cache = v_cache,
+                .seq_len = 0,
+                .max_seq_len = max_seq_len,
+                .num_kv_heads = config.num_key_value_heads,
+                .head_dim = config.head_dim,
+            };
+
+            if (i % 10 == 0 or i == config.n_layers - 1) {
+                log.info("  Initialized layer {}/{}", .{ i + 1, config.n_layers });
+            }
+        }
+
+        self.* = Self{
+            .allocator = allocator,
+            .layers = layers,
+            .config = config,
+            .max_seq_len = max_seq_len,
+            .cache_type = cache_type,
+        };
+
+        log.info("KV cache initialized successfully", .{});
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        for (self.layers) |*layer| {
+            self.allocator.free(layer.k_cache);
+            self.allocator.free(layer.v_cache);
+        }
+        self.allocator.free(self.layers);
+        self.allocator.destroy(self);
+    }
+
+    /// Get KV cache for a specific layer
+    pub fn getLayer(self: *Self, layer_idx: u32) *LayerKVCache {
+        if (layer_idx >= self.layers.len) {
+            std.debug.panic("Layer index {} out of range (n_layers={})", .{ layer_idx, self.layers.len });
+        }
+        return &self.layers[layer_idx];
+    }
+
+    /// Get current sequence length (minimum across all layers)
+    pub fn getSeqLen(self: *const Self) u32 {
+        var min_seq_len: u32 = self.max_seq_len;
+        for (self.layers) |*layer| {
+            min_seq_len = @min(min_seq_len, layer.seq_len);
+        }
+        return min_seq_len;
+    }
+
+    /// Rollback all layers to a specific sequence length
+    /// Used when speculation is rejected and we need to discard draft tokens
+    pub fn rollbackAll(self: *Self, new_seq_len: u32) void {
+        log.debug("Rolling back KV cache from {} to {}", .{ self.getSeqLen(), new_seq_len });
+
+        for (self.layers) |*layer| {
+            layer.rollback(new_seq_len);
+        }
+    }
+
+    /// Clear all KV caches (reset to empty)
+    pub fn clearAll(self: *Self) void {
+        log.debug("Clearing all KV caches", .{});
+
+        for (self.layers) |*layer| {
+            layer.seq_len = 0;
+        }
+    }
+
+    /// Get memory usage in bytes
+    pub fn getMemoryUsage(self: *const Self) usize {
+        const kv_dim = self.config.num_key_value_heads * self.config.head_dim;
+        const elements_per_cache = self.max_seq_len * kv_dim;
+        const bytes_per_cache = elements_per_cache * @sizeOf(BF16);
+        const bytes_per_layer = bytes_per_cache * 2; // K + V
+        return bytes_per_layer * self.config.n_layers;
+    }
+
+    /// Print cache statistics
+    pub fn printStats(self: *const Self) void {
+        const total_mb = @as(f32, @floatFromInt(self.getMemoryUsage())) / (1024.0 * 1024.0);
+        const seq_len = self.getSeqLen();
+        const utilization = @as(f32, @floatFromInt(seq_len)) / @as(f32, @floatFromInt(self.max_seq_len)) * 100.0;
+
+        std.debug.print("\n=== KV Cache Stats ===\n", .{});
+        std.debug.print("Layers: {}\n", .{self.layers.len});
+        std.debug.print("Sequence length: {} / {} ({d:.1}% utilized)\n", .{
+            seq_len,
+            self.max_seq_len,
+            utilization,
+        });
+        std.debug.print("Cache type: {s}\n", .{self.cache_type.toString()});
+        std.debug.print("Total memory: {d:.1} MB\n", .{total_mb});
+        std.debug.print("Per-layer memory: {d:.1} MB\n", .{total_mb / @as(f32, @floatFromInt(self.layers.len))});
+    }
+};
+
+/// Checkpoint for KV cache state (for rollback)
+pub const KVCacheCheckpoint = struct {
+    /// Sequence length at checkpoint time
+    seq_len: u32,
+
+    /// Layer index (for partial checkpoints)
+    layer_idx: u32,
+};
+
+/// Create a checkpoint of current KV cache state
+pub fn createCheckpoint(cache: *LayerSplitKVCache) KVCacheCheckpoint {
+    return KVCacheCheckpoint{
+        .seq_len = cache.getSeqLen(),
+        .layer_idx = 0,
+    };
+}
+
+/// Restore KV cache to checkpoint state
+pub fn restoreCheckpoint(cache: *LayerSplitKVCache, checkpoint: KVCacheCheckpoint) void {
+    cache.rollbackAll(checkpoint.seq_len);
+}

