+//! Layer-Split Speculative Decoding Coordinator
+//!
+//! Orchestrates the draft/verify cycle using a single model with split execution:
+//! - Draft: First N layers (GPU) → early LM head → candidate tokens
+//! - Verify: All layers (GPU + SSD) → final LM head → verify candidates
+//!
+//! High acceptance rate (~70%) because same model = same weights.
+//! Target speedup: 10-30x over baseline SSD streaming.
+
+const std = @import("std");
+const layer_split_engine = @import("layer_split_inference.zig");
+const kv_cache_mod = @import("layer_split_kv_cache.zig");
+const gguf = @import("gguf_loader.zig");
+
+const LayerSplitEngine = layer_split_engine.LayerSplitEngine;
+const BF16 = gguf.BF16;
+const KVCacheCheckpoint = kv_cache_mod.KVCacheCheckpoint;
+
+const log = std.log.scoped(.layer_split_spec);
+
+/// Configuration for layer-split speculative decoding
+pub const LayerSplitSpecConfig = struct {
+    /// Initial speculation depth (will adapt at runtime)
+    speculation_depth: u32 = 8,
+
+    /// Minimum speculation depth
+    min_depth: u32 = 2,
+
+    /// Maximum speculation depth
+    max_depth: u32 = 16,
+
+    /// Temperature for sampling (0.0 = greedy)
+    temperature: f32 = 0.0,
+
+    /// Maximum tokens to generate
+    max_tokens: u32 = 256,
+
+    /// Enable adaptive depth based on acceptance rate
+    adaptive_depth: bool = true,
+
+    /// Minimum acceptance rate to continue speculating
+    min_acceptance_rate: f32 = 0.3,
+
+    /// Window size for tracking recent acceptance rate
+    acceptance_window: u32 = 5,
+};
+
+/// Speculative decoding statistics
+pub const SpeculativeStats = struct {
+    total_tokens: u64 = 0,
+    accepted_tokens: u64 = 0,
+    rejected_tokens: u64 = 0,
+    speculation_rounds: u64 = 0,
+    draft_time_ns: u64 = 0,
+    verify_time_ns: u64 = 0,
+
+    pub fn getAcceptanceRate(self: *const SpeculativeStats) f32 {
+        if (self.total_tokens == 0) return 0.0;
+        return @as(f32, @floatFromInt(self.accepted_tokens)) / @as(f32, @floatFromInt(self.total_tokens));
+    }
+
+    pub fn getSpeedup(self: *const SpeculativeStats, baseline_tok_per_sec: f32) f32 {
+        const total_time_sec = @as(f32, @floatFromInt(self.draft_time_ns + self.verify_time_ns)) / 1_000_000_000.0;
+        if (total_time_sec == 0.0) return 0.0;
+
+        const actual_tok_per_sec = @as(f32, @floatFromInt(self.accepted_tokens)) / total_time_sec;
+        return actual_tok_per_sec / baseline_tok_per_sec;
+    }
+
+    pub fn print(self: *const SpeculativeStats) void {
+        const acceptance_rate = self.getAcceptanceRate();
+        const avg_accepted_per_round = if (self.speculation_rounds > 0)
