+/// Layer-split speculative decoding coordinator
+pub const LayerSplitSpeculative = struct {
+    allocator: std.mem.Allocator,
+
+    /// Layer-split inference engine
+    engine: *LayerSplitEngine,
+
+    /// Configuration
+    config: LayerSplitSpecConfig,
+
+    /// Statistics
+    stats: SpeculativeStats,
+
+    /// Adaptive depth tracking (fixed-size circular buffer for now)
+    recent_acceptances: [10]u32,
+    acceptance_count: usize,
+    current_depth: u32,
+
+    const Self = @This();
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        engine: *LayerSplitEngine,
+        config: LayerSplitSpecConfig,
+    ) !*Self {
+        const self = try allocator.create(Self);
+
+        self.* = Self{
+            .allocator = allocator,
+            .engine = engine,
+            .config = config,
+            .stats = .{},
+            .recent_acceptances = [_]u32{0} ** 10,
+            .acceptance_count = 0,
+            .current_depth = config.speculation_depth,
+        };
+
+        log.info("Layer-split speculative decoding initialized", .{});
+        log.info("  Initial depth: {}", .{config.speculation_depth});
+        log.info("  Adaptive: {}", .{config.adaptive_depth});
+
+        return self;
+    }
+
+    pub fn deinit(self: *Self) void {
+        self.allocator.destroy(self);
+    }
+
+    /// Generate tokens from prompt token IDs
+    pub fn generateFromTokens(
+        self: *Self,
+        prompt_tokens: []const u32,
+        on_token: ?*const fn (token_id: u32) void,
+    ) !void {
+        log.info("Starting generation from {} prompt tokens (max_tokens={})", .{
+            prompt_tokens.len,
+            self.config.max_tokens,
+        });
+
+        // Clear KV cache at start
+        self.engine.clearKVCache();
+
+        // Process prompt tokens (fill KV cache)
+        log.info("Processing prompt tokens...", .{});
+        for (prompt_tokens, 0..) |token_id, i| {
+            log.info("Processing token {}/{}: id={}", .{i + 1, prompt_tokens.len, token_id});
+            const embedding = self.engine.getTokenEmbedding(token_id);
+            log.info("Got embedding, calling draftForward at position {}", .{i});
+            _ = try self.engine.draftForward(embedding, @intCast(i));
+            log.info("Completed token {}", .{i});
+        }
+
+        var position: u32 = @intCast(prompt_tokens.len);
+        var tokens_generated: u32 = 0;
+        var last_token = prompt_tokens[prompt_tokens.len - 1];
+
+        // Main speculative loop
+        while (tokens_generated < self.config.max_tokens) {
+            self.stats.speculation_rounds += 1;
+
+            // Create KV cache checkpoint before drafting
+            const checkpoint = self.engine.createKVCheckpoint();
+
+            // 🚀 JIT PREFETCH: Start loading ALL target layers RIGHT NOW
+            // This runs WHILE we're drafting, creating perfect overlap
+            // ONE massive sequential request = 6 GB/s (vs 260 MB/s with 133 threads)
+            self.engine.stream_engine.prefetchAllTargetLayersJIT();
+
+            // DRAFT PHASE: Generate K candidate tokens using first N layers
+            // The SSD is screaming in the background loading layers 13-31
+            const draft_start = std.time.nanoTimestamp();
+            const candidates = try self.draftPhase(last_token, position);
+            defer self.allocator.free(candidates);
+            const draft_time: u64 = @intCast(std.time.nanoTimestamp() - draft_start);
+            self.stats.draft_time_ns += draft_time;
+
+            if (candidates.len == 0) {
+                log.info("Draft phase produced no candidates, ending generation", .{});
+                break;
+            }
+
+            // log.debug("Draft: {} candidates in {} ms", .{candidates.len, draft_time / 1_000_000});
+
+            // VERIFY PHASE: Verify candidates using all layers
+            const verify_start = std.time.nanoTimestamp();
+            const accepted_count = try self.verifyPhase(
+                last_token,
+                position,
+                candidates,
+            );
+            const verify_time: u64 = @intCast(std.time.nanoTimestamp() - verify_start);
+            self.stats.verify_time_ns += verify_time;
+
+            // log.debug("Verify: {}/{} accepted in {} ms", .{accepted_count, candidates.len, verify_time / 1_000_000});
+
+            // Update statistics
+            self.stats.total_tokens += @intCast(candidates.len);
+            self.stats.accepted_tokens += accepted_count;
+            self.stats.rejected_tokens += @intCast(candidates.len - accepted_count);
+
+            // Track acceptance for adaptive depth (circular buffer)
+            const window = @min(self.config.acceptance_window, 10);
+            if (self.acceptance_count < window) {
+                self.recent_acceptances[self.acceptance_count] = @intCast(accepted_count);
+                self.acceptance_count += 1;
+            } else {
+                // Shift left and add at end
+                for (0..window - 1) |i| {
+                    self.recent_acceptances[i] = self.recent_acceptances[i + 1];
+                }
+                self.recent_acceptances[window - 1] = @intCast(accepted_count);
+            }
+
+            // If no tokens accepted, rollback KV cache
+            if (accepted_count == 0) {
+                log.warn("No tokens accepted, rolling back", .{});
+                self.engine.restoreKVCheckpoint(checkpoint);
+
+                // Sample one token from verify logits
+                // TODO: Implement single token fallback
+                last_token = candidates[0]; // Use first candidate as fallback
+                if (on_token) |callback| {
+                    callback(last_token);
+                }
+            } else {
+                // Update last_token to last accepted candidate
+                last_token = candidates[accepted_count - 1];
+
+                // Call callback for each accepted token
+                if (on_token) |callback| {
+                    for (candidates[0..accepted_count]) |token| {
+                        callback(token);
+                    }
+                }
+            }
+
+            // Update position and check for completion
+            position += @max(accepted_count, 1);
+            tokens_generated += @max(accepted_count, 1);
+
+            // Adapt speculation depth if enabled
+            if (self.config.adaptive_depth) {
+                self.adaptDepth();
+            }
+
+            // Log progress
+            if (tokens_generated % 10 == 0) {
+                const acceptance_rate = self.stats.getAcceptanceRate();
+                log.info("Generated {}/{} tokens (acceptance: {d:.1}%, depth: {})", .{
+                    tokens_generated,
+                    self.config.max_tokens,
+                    acceptance_rate * 100.0,
+                    self.current_depth,
+                });
+            }
+        }
+
+        log.info("Generation complete: {} tokens", .{tokens_generated});
+    }
+
+    /// Draft phase: Generate K candidate tokens using first N layers
+    fn draftPhase(
+        self: *Self,
+        last_token_id: u32,
+        position: u32,
+    ) ![]u32 {
+        const K = @min(self.current_depth, self.config.max_depth);
+        var candidates = try self.allocator.alloc(u32, K);
+        errdefer self.allocator.free(candidates);
+
+        var candidate_count: usize = 0;
+        var current_pos = position;
+        var current_token = last_token_id;
+
+        // Generate K tokens
+        for (0..K) |_| {
+            // Get embedding for current token
+            const embedding = self.engine.getTokenEmbedding(current_token);
+
+            // Run draft forward pass
+            const logits = try self.engine.draftForward(embedding, current_pos);
+
+            // Sample token from logits
+            const token = sampleToken(logits, self.config.temperature);
+
+            // Check for EOS
+            if (self.isEOS(token)) {
+                break;
+            }
+
+            candidates[candidate_count] = token;
+            candidate_count += 1;
+            current_pos += 1;
+            current_token = token; // Use sampled token for next iteration
+        }
+
+        // Trim to actual count
+        if (candidate_count < K) {
+            const trimmed = try self.allocator.realloc(candidates, candidate_count);
+            return trimmed;
+        }
+
+        return candidates;
+    }
+
+    /// Verify phase: Verify K candidates using all layers
+    fn verifyPhase(
+        self: *Self,
+        last_token_id: u32,
+        position: u32,
+        candidates: []const u32,
+    ) !u32 {
+        // Get embedding for starting token
+        const embedding = self.engine.getTokenEmbedding(last_token_id);
+
+        // Run verify forward pass for all K tokens
+        const all_logits = try self.engine.verifyForward(
+            embedding,
+            position,
+            @intCast(candidates.len),
+        );
+        defer {
+            for (all_logits) |logits| {
+                self.allocator.free(logits);
+            }
+            self.allocator.free(all_logits);
+        }
+
+        // Check each candidate against verified logits
+        var accepted: u32 = 0;
+        for (candidates, 0..) |candidate_token, i| {
+            const logits = all_logits[i];
+            const verified_token = sampleToken(logits, self.config.temperature);
+
+            if (verified_token == candidate_token) {
+                accepted += 1;
+            } else {
+                // Mismatch - stop here and resample from verified logits
+                break;
+            }
+        }
+
+        return accepted;
+    }
+
+    /// Adapt speculation depth based on recent acceptance rate
+    fn adaptDepth(self: *Self) void {
+        const window = @min(self.config.acceptance_window, 10);
+        if (self.acceptance_count < window) {
+            return; // Not enough data yet
+        }
+
+        // Calculate average acceptance
+        var sum: u32 = 0;
+        for (self.recent_acceptances[0..window]) |count| {
+            sum += count;
+        }
+        const avg_accepted = @as(f32, @floatFromInt(sum)) / @as(f32, @floatFromInt(window));
+        const acceptance_rate = avg_accepted / @as(f32, @floatFromInt(self.current_depth));
+
+        // Adjust depth based on acceptance rate
+        if (acceptance_rate > 0.7 and self.current_depth < self.config.max_depth) {
+            // High acceptance - increase depth
+            self.current_depth = @min(self.current_depth + 2, self.config.max_depth);
+            // log.debug("Increasing depth to {} (acceptance: {d:.1}%)", .{self.current_depth, acceptance_rate * 100.0});
+        } else if (acceptance_rate < 0.3 and self.current_depth > self.config.min_depth) {
+            // Low acceptance - decrease depth
+            self.current_depth = @max(self.current_depth - 2, self.config.min_depth);
+            // log.debug("Decreasing depth to {} (acceptance: {d:.1}%)", .{self.current_depth, acceptance_rate * 100.0});
+        }
+    }
+
+    /// Check if token is end-of-sequence
+    fn isEOS(self: *const Self, token: u32) bool {
+        _ = self;
+        // TODO: Get EOS token ID from vocabulary
+        // For now, assume 0 is not EOS (placeholder)
+        return token == 0;
+    }
+
+    /// Print statistics
+    pub fn printStats(self: *const Self) void {
+        self.stats.print();
+    }
+};
+
+/// Sample a token from logits with temperature
+fn sampleToken(logits: []const f32, temperature: f32) u32 {
+    if (temperature == 0.0) {
+        // Greedy sampling
+        return greedySample(logits);
+    } else {
+        // Temperature sampling
+        return temperatureSample(logits, temperature);
+    }
+}
+
+/// Greedy sampling: Return argmax token
+fn greedySample(logits: []const f32) u32 {
+    var max_idx: u32 = 0;
+    var max_val = logits[0];
+
+    for (logits, 0..) |logit, i| {
+        if (logit > max_val) {
+            max_val = logit;
+            max_idx = @intCast(i);
+        }
+    }
+
+    return max_idx;
+}
+
+/// Temperature sampling: Sample from softmax distribution
+fn temperatureSample(logits: []const f32, temperature: f32) u32 {
+    _ = temperature;
+    // TODO: Implement proper temperature sampling with softmax
+    // For now, fall back to greedy
+    return greedySample(logits);
+}

