+const std = @import("std");
+const profile = @import("profile.zig");
+const builtin = @import("builtin");
+
+/// Configuration for layer-split speculative decoding
+/// Single model split: first N layers on GPU (draft), remaining layers on SSD (verify)
+pub const LayerSplitConfig = struct {
+    /// Total number of layers in the model
+    total_layers: u32,
+
+    /// Number of layers to load on GPU for draft inference (fast)
+    draft_layers: u32,
+
+    /// Number of layers to stream from SSD for verification (slow but batched)
+    target_layers: u32,
+
+    /// Available GPU memory budget (GB)
+    gpu_memory_gb: f32,
+
+    /// Whether to use the shared LM head (zero additional memory)
+    /// If false, would need to train a separate early-exit head
+    use_shared_lm_head: bool = true,
+
+    /// Temperature scaling for early logits (typically 1.0)
+    early_exit_scale: f32 = 1.0,
+
+    /// Speculation depth (how many tokens to draft at once)
+    speculation_depth: u32 = 8,
+
+    /// Minimum acceptance rate to continue using speculation
+    min_acceptance_rate: f32 = 0.5,
+};
+
+/// Calculate optimal layer split based on model size and available memory
+/// Uses precise memory accounting for all components
+pub fn calculateOptimalSplit(
+    model_info: profile.ModelInfo,
+    available_memory_gb: f32,
+) LayerSplitConfig {
+    return calculateOptimalSplitWithContext(model_info, available_memory_gb, 2048);
+}
+
+/// Calculate optimal split with explicit context size
+pub fn calculateOptimalSplitWithContext(
+    model_info: profile.ModelInfo,
+    available_memory_gb: f32,
+    n_ctx: u32,
+) LayerSplitConfig {
+    // Per-layer memory requirement
+    const layer_size_gb = model_info.size_gb / @as(f32, @floatFromInt(model_info.n_layers));
+
+    // Fixed memory costs (independent of draft layer count)
+    const token_embd_gb = @as(f32, @floatFromInt(model_info.n_vocab * model_info.n_embd * 2)) / (1024.0 * 1024.0 * 1024.0);
+    const lm_head_gb = token_embd_gb; // Same size
+
+    // KV cache: 2 caches (K+V) × n_ctx × kv_heads × head_dim × 2 bytes × n_layers
+    const kv_heads = 8; // Typical for large models
+    const head_dim = 128; // Standard
+    const kv_dim = kv_heads * head_dim;
+    const kv_cache_gb = @as(f32, @floatFromInt(model_info.n_layers * 2 * n_ctx * kv_dim * 2)) / (1024.0 * 1024.0 * 1024.0);
+
+    const working_buffers_gb: f32 = 0.15; // Hidden states, FFN buffers, logits
+
+    // Streaming ping-pong buffers: 2 layer buffers, but use Q8 (53% of BF16)
+    const pingpong_gb = layer_size_gb * 2.0 * 0.53;
+
+    // Fixed overhead
+    const fixed_overhead_gb = token_embd_gb + lm_head_gb + kv_cache_gb + working_buffers_gb + pingpong_gb;
+
+    // Available for draft layers
+    const available_for_draft = @max(0.0, available_memory_gb - fixed_overhead_gb);
+
+    // Calculate how many draft layers fit
+    const draft_layers_float = available_for_draft / layer_size_gb;
+    var draft_layers = @as(u32, @intFromFloat(@floor(draft_layers_float)));
+
+    // Clamp to reasonable range:
+    // - Minimum: 20% of layers (need some GPU computation)
+    // - Maximum: 75% of layers (need enough target layers for quality)
+    const min_draft = @max(1, model_info.n_layers / 5);
+    const max_draft = (model_info.n_layers * 3) / 4;
+    draft_layers = @max(min_draft, @min(draft_layers, max_draft));
+
+    const target_layers = model_info.n_layers - draft_layers;
+    const draft_memory_gb = layer_size_gb * @as(f32, @floatFromInt(draft_layers));
+    const total_memory_gb = fixed_overhead_gb + draft_memory_gb;
+
+    std.debug.print("🧮 Layer split calculation:\n", .{});
+    std.debug.print("  Model: {} layers, {d:.1} GB total\n", .{ model_info.n_layers, model_info.size_gb });
+    std.debug.print("  Per-layer size: {d:.2} GB\n\n", .{layer_size_gb});
+
+    std.debug.print("  Fixed overhead:\n", .{});
+    std.debug.print("    Token embeddings: {d:.2} GB\n", .{token_embd_gb});
+    std.debug.print("    LM head:          {d:.2} GB\n", .{lm_head_gb});
+    std.debug.print("    KV cache ({}):   {d:.2} GB\n", .{n_ctx, kv_cache_gb});
+    std.debug.print("    Working buffers:  {d:.2} GB\n", .{working_buffers_gb});
+    std.debug.print("    Ping-pong (Q8):   {d:.2} GB\n", .{pingpong_gb});
+    std.debug.print("    Subtotal:         {d:.2} GB\n\n", .{fixed_overhead_gb});
+
+    std.debug.print("  Available memory: {d:.1} GB\n", .{available_memory_gb});
+    std.debug.print("  Available for draft layers: {d:.2} GB\n", .{available_for_draft});
+    std.debug.print("  Draft layers: {} (0-{})\n", .{draft_layers, draft_layers - 1});
+    std.debug.print("  Draft memory: {d:.2} GB\n\n", .{draft_memory_gb});
+
+    std.debug.print("  ✓ Total memory usage: {d:.2} GB / {d:.1} GB\n", .{total_memory_gb, available_memory_gb});
+    std.debug.print("  ✓ Margin: {d:.2} GB\n\n", .{available_memory_gb - total_memory_gb});
+
+    std.debug.print("  → Draft layers: 0-{} ({d:.1} GB on GPU/RAM)\n", .{ draft_layers - 1, draft_memory_gb });
+    std.debug.print("  → Target layers: {}-{} ({d:.1} GB on SSD)\n", .{
+        draft_layers,
+        model_info.n_layers - 1,
+        layer_size_gb * @as(f32, @floatFromInt(target_layers))
+    });
+
+    return LayerSplitConfig{
+        .total_layers = model_info.n_layers,
+        .draft_layers = draft_layers,
+        .target_layers = target_layers,
+        .gpu_memory_gb = available_memory_gb,
+    };
+}
+
+/// Check if layer-split is beneficial for this model/system configuration
+pub fn shouldUseLayerSplit(
+    model_info: profile.ModelInfo,
+    system_memory_gb: f32,
+) bool {
+    // Use layer-split when:
+    // 1. Model is larger than 80% of system RAM (won't fit comfortably)
+    // 2. Model has enough layers to split (at least 16 layers)
+    const model_too_large = model_info.size_gb > (system_memory_gb * 0.8);
+    const enough_layers = model_info.n_layers >= 16;
+
+    return model_too_large and enough_layers;
+}
+
+/// Get available memory on the system (GB)
+/// Returns memory available for ML workloads after accounting for OS overhead
+pub fn getAvailableMemoryGB(allocator: std.mem.Allocator) !f32 {
+    if (builtin.os.tag == .macos) {
+        // Use sysctl to get actual memory info on macOS
+        const result = std.process.Child.run(.{
+            .allocator = allocator,
+            .argv = &[_][]const u8{ "sysctl", "-n", "hw.memsize" },
+        }) catch {
+            // Fallback: assume 16GB if sysctl fails
+            std.debug.print("⚠️  Could not detect memory, assuming 16GB\n", .{});
+            return 14.4; // 16GB - 10% overhead
+        };
+        defer allocator.free(result.stdout);
+        defer allocator.free(result.stderr);
+
+        const bytes = std.fmt.parseInt(u64, std.mem.trim(u8, result.stdout, " \n"), 10) catch {
+            std.debug.print("⚠️  Could not parse memory size, assuming 16GB\n", .{});
+            return 14.4;
+        };
+
+        const total_gb = @as(f32, @floatFromInt(bytes)) / (1024.0 * 1024.0 * 1024.0);
+
+        // Reserve 10% for OS + some safety margin
+        const available_gb = total_gb * 0.90;
+
+        std.debug.print("💾 System memory: {d:.1} GB total, {d:.1} GB available for ML\n", .{total_gb, available_gb});
+
+        return available_gb;
+    } else {
+        // Linux: read from /proc/meminfo
+        const meminfo = std.fs.cwd().openFile("/proc/meminfo", .{}) catch {
+            std.debug.print("⚠️  Could not read /proc/meminfo, assuming 16GB\n", .{});
+            return 14.4;
+        };
+        defer meminfo.close();
+
+        var buf: [1024]u8 = undefined;
+        const len = meminfo.readAll(&buf) catch {
+            return 14.4;
+        };
+
+        // Parse MemTotal line
+        var it = std.mem.split(u8, buf[0..len], "\n");
+        while (it.next()) |line| {
+            if (std.mem.startsWith(u8, line, "MemTotal:")) {
+                var parts = std.mem.tokenize(u8, line, " ");
+                _ = parts.next(); // Skip "MemTotal:"
+                if (parts.next()) |kb_str| {
+                    const kb = std.fmt.parseInt(u64, kb_str, 10) catch continue;
+                    const total_gb = @as(f32, @floatFromInt(kb)) / (1024.0 * 1024.0);
+                    const available_gb = total_gb * 0.90;
+
+                    std.debug.print("💾 System memory: {d:.1} GB total, {d:.1} GB available\n", .{total_gb, available_gb});
+                    return available_gb;
+                }
+            }
+        }
+
+        return 14.4; // Fallback
+    }
+}
+
+/// Estimate performance improvement from layer-split speculation
+pub fn estimateSpeedup(
+    config: LayerSplitConfig,
+    draft_tok_per_sec: f32,
+    target_tok_per_sec: f32,
+    expected_acceptance_rate: f32,
+) f32 {
+    // Without speculation: target_tok_per_sec
+    const baseline_speed = target_tok_per_sec;
+
+    // With speculation:
+    // - Draft K tokens: K / draft_tok_per_sec
+    // - Verify K tokens in batch: 1 / target_tok_per_sec (amortized)
+    // - Accepted: K * acceptance_rate
+    const K = @as(f32, @floatFromInt(config.speculation_depth));
+    const draft_time = K / draft_tok_per_sec;
+    const verify_time = 1.0 / target_tok_per_sec;
+    const accepted = K * expected_acceptance_rate;
+    const speculation_speed = accepted / (draft_time + verify_time);
+
+    const speedup = speculation_speed / baseline_speed;
+    return speedup;
+}
