+/// Preprocess draft layers: dequantize from Q8/Q4 → BF16 and save to cache
+/// This makes startup instant (5 sec mmap) instead of slow (2-3 min dequantization)
+/// Returns the path to the cached file, or error if preprocessing fails
+pub fn preprocessDraftLayers(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    config: LayerSplitConfig,
+) ![]const u8 {
+    const model_hash_mod = @import("model_hash.zig");
+
+    // Generate cache path based on model hash and config
+    const cache_path = try model_hash_mod.getDraftLayerCachePath(allocator, model_path, config.draft_layers);
+    errdefer allocator.free(cache_path);
+
+    // Check if cache already exists and is valid
+    if (std.fs.cwd().access(cache_path, .{})) |_| {
+        std.debug.print("  ✅ Using cached draft layers: {s}\n", .{cache_path});
+        return cache_path;
+    } else |_| {
+        // Cache doesn't exist, need to create it
+    }
+
+    std.debug.print("  Dequantizing {} draft layers to BF16...\n", .{config.draft_layers});
+    std.debug.print("  This may take 2-3 minutes (one-time cost)\n", .{});
+
+    const gguf_loader = @import("inference/gguf_loader.zig");
+    const qwen_model = @import("inference/qwen_model.zig");
+
+    // Load GGUF file
+    var loader = gguf_loader.GGUFLoader.init(allocator, model_path) catch |err| {
+        std.debug.print("  ❌ Failed to load GGUF: {}\n", .{err});
+        return err;
+    };
+    defer loader.deinit();
+
+    const model_config = loader.loadQwenConfig(allocator) catch |err| {
+        std.debug.print("  ❌ Failed to load config: {}\n", .{err});
+        return err;
+    };
+
+    // Create cache file
+    const cache_file = std.fs.cwd().createFile(cache_path, .{}) catch |err| {
+        std.debug.print("  ❌ Failed to create cache file: {}\n", .{err});
+        return err;
+    };
+    defer cache_file.close();
+
+    var name_buf: [128]u8 = undefined;
+
+    // Detect if MoE (check for expert 0 in layer 0)
+    const test_name = std.fmt.bufPrint(&name_buf, "blk.0.ffn_gate_inp.weight", .{}) catch unreachable;
+    const is_moe = loader.getTensor(test_name) != null;
+
+    if (is_moe) {
+        std.debug.print("  Detected MoE architecture (8 experts per layer)\n", .{});
+    }
+
+    // Process each draft layer
+    for (0..config.draft_layers) |layer_idx| {
+        const layer = @as(u32, @intCast(layer_idx));
+        std.debug.print("  Layer {}/{}: ", .{ layer + 1, config.draft_layers });
+
+        // Load and save each tensor for this layer
+        // 1. LayerNorms
+        const ln1 = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.input_layernorm, layer, model_config.hidden_size);
+        defer allocator.free(ln1);
+        try cache_file.writeAll(std.mem.sliceAsBytes(ln1));
+
+        const ln2 = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.post_attn_layernorm, layer, model_config.hidden_size);
+        defer allocator.free(ln2);
+        try cache_file.writeAll(std.mem.sliceAsBytes(ln2));
+
+        // 2. Attention weights
+        const q_proj = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.q_proj, layer, model_config.hidden_size * model_config.hidden_size);
+        defer allocator.free(q_proj);
+        try cache_file.writeAll(std.mem.sliceAsBytes(q_proj));
+
+        const k_proj = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.k_proj, layer, model_config.hidden_size * model_config.kv_dim);
+        defer allocator.free(k_proj);
+        try cache_file.writeAll(std.mem.sliceAsBytes(k_proj));
+
+        const v_proj = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.v_proj, layer, model_config.hidden_size * model_config.kv_dim);
+        defer allocator.free(v_proj);
+        try cache_file.writeAll(std.mem.sliceAsBytes(v_proj));
+
+        const o_proj = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.o_proj, layer, model_config.hidden_size * model_config.hidden_size);
+        defer allocator.free(o_proj);
+        try cache_file.writeAll(std.mem.sliceAsBytes(o_proj));
+
+        // 3. FFN weights (MoE or dense)
+        if (is_moe) {
+            // MoE: save router + 8 experts
+            const router_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_gate_inp.weight", .{layer}) catch unreachable;
+            const router = try loadAndDequantizeTensorByName(allocator, &loader, router_name, model_config.hidden_size * 8);
+            defer allocator.free(router);
+            try cache_file.writeAll(std.mem.sliceAsBytes(router));
+
+            for (0..8) |expert_idx| {
+                const gate_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_gate.{d}.weight", .{ layer, expert_idx }) catch unreachable;
+                const up_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_up.{d}.weight", .{ layer, expert_idx }) catch unreachable;
+                const down_name = std.fmt.bufPrint(&name_buf, "blk.{d}.ffn_down.{d}.weight", .{ layer, expert_idx }) catch unreachable;
+
+                const gate = try loadAndDequantizeTensorByName(allocator, &loader, gate_name, model_config.hidden_size * model_config.intermediate_size);
