+                const up = try loadAndDequantizeTensorByName(allocator, &loader, up_name, model_config.hidden_size * model_config.intermediate_size);
+                defer allocator.free(up);
+                try cache_file.writeAll(std.mem.sliceAsBytes(up));
+
+                const down = try loadAndDequantizeTensorByName(allocator, &loader, down_name, model_config.intermediate_size * model_config.hidden_size);
+                defer allocator.free(down);
+                try cache_file.writeAll(std.mem.sliceAsBytes(down));
+            }
+            std.debug.print("MoE (8 experts)\n", .{});
+        } else {
+            // Dense: save gate/up/down
+            const gate = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.gate_proj, layer, model_config.hidden_size * model_config.intermediate_size);
+            defer allocator.free(gate);
+            try cache_file.writeAll(std.mem.sliceAsBytes(gate));
+
+            const up = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.up_proj, layer, model_config.hidden_size * model_config.intermediate_size);
+            defer allocator.free(up);
+            try cache_file.writeAll(std.mem.sliceAsBytes(up));
+
+            const down = try loadAndDequantizeTensor(allocator, &loader, &name_buf, qwen_model.GGUFNames.down_proj, layer, model_config.intermediate_size * model_config.hidden_size);
+            defer allocator.free(down);
+            try cache_file.writeAll(std.mem.sliceAsBytes(down));
+
+            std.debug.print("Dense FFN\n", .{});
+        }
+    }
+
+    std.debug.print("  ✅ Draft layers cached successfully\n", .{});
+    return cache_path;
+}
