+/// Helper: Load and dequantize a tensor by template name
+fn loadAndDequantizeTensor(
+    allocator: std.mem.Allocator,
+    loader: *@import("inference/gguf_loader.zig").GGUFLoader,
+    name_buf: []u8,
+    comptime template: []const u8,
+    layer: u32,
+    size: usize,
