+const std = @import("std");
+const gguf_loader = @import("inference/gguf_loader.zig");
+
+/// Mixture of Experts (MoE) implementation for Mixtral-style models
+///
+/// Architecture:
+/// - Router network selects top-K experts per token
+/// - Each expert is a standard FFN with SwiGLU activation
+/// - Expert outputs are weighted and combined
+///
+/// Tensor naming convention (for layer i, expert j):
+/// - blk.{i}.ffn_gate_inp.weight: Router matrix [n_embd, n_expert]
+/// - blk.{i}.ffn_gate.{j}.weight: Expert j gate (SwiGLU) [n_ff, n_embd]
+/// - blk.{i}.ffn_up.{j}.weight: Expert j up projection [n_ff, n_embd]
+/// - blk.{i}.ffn_down.{j}.weight: Expert j down projection [n_embd, n_ff]
+
+/// MoE layer configuration
+pub const MoEConfig = struct {
+    n_expert: u32, // Total number of experts (e.g., 8 for Mixtral)
+    n_expert_used: u32, // Number of experts selected per token (e.g., 2 for Mixtral)
+    n_embd: u32, // Embedding dimension
+    n_ff: u32, // FFN intermediate dimension
+};
+
+/// Expert selection result (router output)
+pub const ExpertSelection = struct {
+    expert_ids: []u32, // Shape: [n_expert_used, n_tokens]
+    expert_weights: []f32, // Shape: [n_expert_used, n_tokens]
+    allocator: std.mem.Allocator,
+
+    pub fn deinit(self: *ExpertSelection) void {
+        self.allocator.free(self.expert_ids);
+        self.allocator.free(self.expert_weights);
+    }
+};
+
+/// MoE Router: Selects top-K experts for each token
+///
+/// Input:
+///   hidden_states: [n_embd, n_tokens]
+///   router_weights: [n_expert, n_embd]
+///
+/// Output:
+///   ExpertSelection with top-K expert IDs and weights per token
+pub fn routeExperts(
+    allocator: std.mem.Allocator,
+    hidden_states: []const f32,
+    router_weights: []const f32,
+    config: MoEConfig,
+    n_tokens: usize,
+) !ExpertSelection {
+    const n_expert = config.n_expert;
+    const n_expert_used = config.n_expert_used;
+    const n_embd = config.n_embd;
+
+    // Compute router logits: [n_expert, n_tokens]
+    var router_logits = try allocator.alloc(f32, n_expert * n_tokens);
+    defer allocator.free(router_logits);
+
+    // Matrix multiplication: router_weights @ hidden_states
+    for (0..n_expert) |e| {
+        for (0..n_tokens) |t| {
+            var sum: f32 = 0.0;
+            for (0..n_embd) |d| {
+                const w = router_weights[e * n_embd + d];
+                const h = hidden_states[d * n_tokens + t];
+                sum += w * h;
+            }
+            router_logits[e * n_tokens + t] = sum;
+        }
+    }
+
+    // Apply softmax and select top-K experts per token
+    var expert_ids = try allocator.alloc(u32, n_expert_used * n_tokens);
+    var expert_weights = try allocator.alloc(f32, n_expert_used * n_tokens);
+
+    for (0..n_tokens) |t| {
+        // Get logits for this token
+        var token_logits = try allocator.alloc(f32, n_expert);
+        defer allocator.free(token_logits);
+
+        for (0..n_expert) |e| {
+            token_logits[e] = router_logits[e * n_tokens + t];
+        }
+
+        // Find top-K experts (simple selection sort for small K)
+        var selected_experts = try allocator.alloc(u32, n_expert_used);
+        defer allocator.free(selected_experts);
+
+        for (0..n_expert_used) |k| {
+            var max_idx: u32 = 0;
+            var max_val: f32 = -std.math.inf(f32);
+
+            for (0..n_expert) |e| {
+                var already_selected = false;
+                for (0..k) |prev| {
+                    if (selected_experts[prev] == e) {
+                        already_selected = true;
+                        break;
+                    }
+                }
+                if (!already_selected and token_logits[e] > max_val) {
+                    max_val = token_logits[e];
+                    max_idx = @intCast(e);
+                }
+            }
+            selected_experts[k] = max_idx;
+        }
+
+        // Compute softmax over selected experts
+        var sum_exp: f32 = 0.0;
+        var selected_logits = try allocator.alloc(f32, n_expert_used);
+        defer allocator.free(selected_logits);
+
+        for (0..n_expert_used) |k| {
+            const expert_idx = selected_experts[k];
+            const logit = token_logits[expert_idx];
+            selected_logits[k] = @exp(logit);
+            sum_exp += selected_logits[k];
+        }
+
+        // Normalize and store results
+        for (0..n_expert_used) |k| {
+            expert_ids[k * n_tokens + t] = selected_experts[k];
+            expert_weights[k * n_tokens + t] = selected_logits[k] / sum_exp;
+        }
+    }
+
+    return ExpertSelection{
+        .expert_ids = expert_ids,
+        .expert_weights = expert_weights,
+        .allocator = allocator,
+    };
+}
+
+/// Single expert FFN computation (SwiGLU activation)
+///
+/// Formula:
+///   gate = gate_proj @ x
+///   up = up_proj @ x
+///   activated = gate * silu(up)
+///   output = down_proj @ activated
+///
+/// Dimensions:
+///   x: [n_embd, n_tokens]
+///   gate_proj: [n_ff, n_embd]
+///   up_proj: [n_ff, n_embd]
+///   down_proj: [n_embd, n_ff]
+///   output: [n_embd, n_tokens]
+fn expertFFN(
+    allocator: std.mem.Allocator,
+    x: []const f32,
+    gate_weights: []const f32,
+    up_weights: []const f32,
+    down_weights: []const f32,
+    n_embd: usize,
+    n_ff: usize,
+    n_tokens: usize,
+) ![]f32 {
+    // Allocate intermediate buffers
+    var gate = try allocator.alloc(f32, n_ff * n_tokens);
+    defer allocator.free(gate);
+    var up = try allocator.alloc(f32, n_ff * n_tokens);
+    defer allocator.free(up);
+
+    // Gate projection: gate_weights @ x
+    for (0..n_ff) |i| {
+        for (0..n_tokens) |t| {
+            var sum: f32 = 0.0;
+            for (0..n_embd) |j| {
+                sum += gate_weights[i * n_embd + j] * x[j * n_tokens + t];
+            }
+            gate[i * n_tokens + t] = sum;
+        }
+    }
+
+    // Up projection: up_weights @ x
+    for (0..n_ff) |i| {
+        for (0..n_tokens) |t| {
+            var sum: f32 = 0.0;
+            for (0..n_embd) |j| {
+                sum += up_weights[i * n_embd + j] * x[j * n_tokens + t];
+            }
+            up[i * n_tokens + t] = sum;
+        }
+    }
+
+    // SwiGLU activation: gate * silu(up)
+    var activated = try allocator.alloc(f32, n_ff * n_tokens);
+    defer allocator.free(activated);
+
+    for (0..n_ff * n_tokens) |i| {
+        const up_val = up[i];
+        const silu = up_val / (1.0 + @exp(-up_val)); // SiLU(x) = x * sigmoid(x)
+        activated[i] = gate[i] * silu;
+    }
+
+    // Down projection: down_weights @ activated
+    var output = try allocator.alloc(f32, n_embd * n_tokens);
+
+    for (0..n_embd) |i| {
+        for (0..n_tokens) |t| {
+            var sum: f32 = 0.0;
+            for (0..n_ff) |j| {
+                sum += down_weights[i * n_ff + j] * activated[j * n_tokens + t];
+            }
+            output[i * n_tokens + t] = sum;
+        }
+    }
+
+    return output;
+}
+
+/// MoE FFN layer: Routes to experts and combines outputs
+///
+/// This is the main entry point for MoE computation.
+///
+/// Input:
+///   x: [n_embd, n_tokens] - Input hidden states
+///   router_weights: [n_expert, n_embd] - Router matrix
+///   expert_weights: Array of expert weight matrices (gate, up, down for each expert)
+///
+/// Output:
+///   [n_embd, n_tokens] - MoE output
+pub fn moeFFN(
+    allocator: std.mem.Allocator,
+    x: []const f32,
+    router_weights: []const f32,
+    expert_gate_weights: [][]const f32, // [n_expert][n_ff * n_embd]
+    expert_up_weights: [][]const f32, // [n_expert][n_ff * n_embd]
+    expert_down_weights: [][]const f32, // [n_expert][n_embd * n_ff]
+    config: MoEConfig,
+    n_tokens: usize,
+) ![]f32 {
+    const n_embd = config.n_embd;
+    const n_ff = config.n_ff;
+    const n_expert_used = config.n_expert_used;
+
+    // Step 1: Route to experts
+    var selection = try routeExperts(allocator, x, router_weights, config, n_tokens);
+    defer selection.deinit();
+
+    // Step 2: Compute expert outputs
+    var expert_outputs = try allocator.alloc([]f32, n_expert_used);
+    defer {
+        for (expert_outputs) |output| {
+            allocator.free(output);
+        }
+        allocator.free(expert_outputs);
+    }
+
+    // Process each selected expert for each token
+    // Note: This is simplified - in practice we'd batch by expert
+    for (0..n_expert_used) |k| {
+        // For now, we'll process the first token's first expert
+        // TODO: Implement full batched expert processing
+        const expert_idx = selection.expert_ids[k * n_tokens]; // Get expert for first token
+
+        expert_outputs[k] = try expertFFN(
+            allocator,
+            x,
+            expert_gate_weights[expert_idx],
+            expert_up_weights[expert_idx],
+            expert_down_weights[expert_idx],
+            n_embd,
+            n_ff,
+            n_tokens,
+        );
+    }
+
+    // Step 3: Weighted combination of expert outputs
+    var output = try allocator.alloc(f32, n_embd * n_tokens);
+    @memset(output, 0.0);
+
+    for (0..n_expert_used) |k| {
+        for (0..n_tokens) |t| {
+            const weight = selection.expert_weights[k * n_tokens + t];
+            for (0..n_embd) |d| {
+                output[d * n_tokens + t] += weight * expert_outputs[k][d * n_tokens + t];
+            }
+        }
+    }
+
+    return output;
+}
+
