+// =============================================================================
+// GGUF Weight Loading for MoE
+// =============================================================================
+
+/// MoE layer weights loaded from GGUF
+pub const MoELayerWeights = struct {
+    router_weights: []const u8, // Raw quantized data
+    expert_gate_weights: [][]const u8, // [n_expert] raw quantized data
+    expert_up_weights: [][]const u8, // [n_expert] raw quantized data
+    expert_down_weights: [][]const u8, // [n_expert] raw quantized data
+    allocator: std.mem.Allocator,
+
+    pub fn deinit(self: *MoELayerWeights) void {
+        self.allocator.free(self.expert_gate_weights);
+        self.allocator.free(self.expert_up_weights);
+        self.allocator.free(self.expert_down_weights);
+    }
+};
+
+/// Load MoE weights for a specific layer from GGUF file
+///
+/// Tensor names follow pattern:
+///   blk.{layer_idx}.ffn_gate_inp.weight - Router
+///   blk.{layer_idx}.ffn_gate.{expert_idx}.weight - Expert gate
+///   blk.{layer_idx}.ffn_up.{expert_idx}.weight - Expert up
+///   blk.{layer_idx}.ffn_down.{expert_idx}.weight - Expert down
+pub fn loadMoELayerWeights(
+    allocator: std.mem.Allocator,
+    loader: *gguf_loader.GGUFLoader,
+    layer_idx: u32,
+    n_expert: u32,
+) !MoELayerWeights {
+    var buf: [256]u8 = undefined;
+
+    // Load router weights
+    const router_name = try std.fmt.bufPrint(&buf, "blk.{d}.ffn_gate_inp.weight", .{layer_idx});
+    const router_data = loader.getTensorDataByName(router_name) orelse {
+        std.log.err("Failed to load router weights for layer {d}", .{layer_idx});
+        return error.TensorNotFound;
+    };
+
+    // Load expert weights
+    var expert_gate_weights = try allocator.alloc([]const u8, n_expert);
+    var expert_up_weights = try allocator.alloc([]const u8, n_expert);
+    var expert_down_weights = try allocator.alloc([]const u8, n_expert);
+
+    for (0..n_expert) |expert_idx| {
+        // Gate weights
+        const gate_name = try std.fmt.bufPrint(&buf, "blk.{d}.ffn_gate.{d}.weight", .{ layer_idx, expert_idx });
+        expert_gate_weights[expert_idx] = loader.getTensorDataByName(gate_name) orelse {
+            std.log.err("Failed to load expert {d} gate weights for layer {d}", .{ expert_idx, layer_idx });
+            return error.TensorNotFound;
+        };
+
+        // Up weights
+        const up_name = try std.fmt.bufPrint(&buf, "blk.{d}.ffn_up.{d}.weight", .{ layer_idx, expert_idx });
+        expert_up_weights[expert_idx] = loader.getTensorDataByName(up_name) orelse {
+            std.log.err("Failed to load expert {d} up weights for layer {d}", .{ expert_idx, layer_idx });
+            return error.TensorNotFound;
+        };
+
+        // Down weights
+        const down_name = try std.fmt.bufPrint(&buf, "blk.{d}.ffn_down.{d}.weight", .{ layer_idx, expert_idx });
+        expert_down_weights[expert_idx] = loader.getTensorDataByName(down_name) orelse {
+            std.log.err("Failed to load expert {d} down weights for layer {d}", .{ expert_idx, layer_idx });
+            return error.TensorNotFound;
+        };
+    }
+
+    return MoELayerWeights{
+        .router_weights = router_data,
+        .expert_gate_weights = expert_gate_weights,
+        .expert_up_weights = expert_up_weights,
+        .expert_down_weights = expert_down_weights,
+        .allocator = allocator,
+    };
+}

