+const std = @import("std");
+const moe = @import("moe.zig");
+const gguf_loader = @import("inference/gguf_loader.zig");
+const profile_mod = @import("profile.zig");
+const llama = @import("llama.zig");
+
+/// MoE-specific inference pipeline
+///
+/// This bypasses llama.cpp's broken MoE support and uses our native Zig
+/// implementation for Mixture-of-Experts models like Mixtral.
+
+/// Run inference on an MoE model using native Zig implementation
+pub fn runMoEInference(
+    allocator: std.mem.Allocator,
+    model_path: []const u8,
+    prompt: []const u8,
+    prof: profile_mod.Profile,
+    opts: struct {
+        max_tokens: usize = 256,
+        temperature: f32 = 0.7,
+    },
+) !void {
+    std.debug.print("\n🚀 Native Zig MoE Inference\n", .{});
+    std.debug.print("Model: {s}\n", .{std.fs.path.basename(model_path)});
+    std.debug.print("Experts: {}\n", .{prof.model_info.n_expert});
+    std.debug.print("Layers: {}\n", .{prof.model_info.n_layers});
+    std.debug.print("\n", .{});
+
+    // Step 1: Load GGUF file
+    std.debug.print("📦 Loading GGUF model...\n", .{});
+    var loader = try gguf_loader.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    std.debug.print("  • Tensors: {}\n", .{loader.tensor_count});
+    std.debug.print("  • Experts: {}\n", .{prof.model_info.n_expert});
+    std.debug.print("\n", .{});
+
+    // Step 2: Tokenize prompt using llama.cpp (just for tokenization, not inference)
+    std.debug.print("🔤 Tokenizing prompt...\n", .{});
+    var model = try llama.Model.load(model_path, .{
+        .n_gpu_layers = 0, // We'll handle GPU ourselves
+        .use_mmap = true,
+    });
+    defer model.deinit();
+
+    const tokens = try llama.tokenize(&model, prompt, true);
+    defer std.c.free(tokens.ptr);
+
+    std.debug.print("  • Tokens: {}\n", .{tokens.len});
+    std.debug.print("  • Prompt: \"{s}\"\n", .{prompt});
+    std.debug.print("\n", .{});
+
+    // Step 3: Load MoE weights for first layer (proof of concept)
+    std.debug.print("⚙️  Loading MoE weights for layer 0...\n", .{});
+    var layer_weights = try moe.loadMoELayerWeights(
+        allocator,
+        &loader,
+        0, // First layer
+        prof.model_info.n_expert,
+    );
+    defer layer_weights.deinit();
+
+    std.debug.print("  • Router weights: {} bytes\n", .{layer_weights.router_weights.len});
+    std.debug.print("  • Expert 0 gate: {} bytes\n", .{layer_weights.expert_gate_weights[0].len});
+    std.debug.print("  • Expert 0 up: {} bytes\n", .{layer_weights.expert_up_weights[0].len});
+    std.debug.print("  • Expert 0 down: {} bytes\n", .{layer_weights.expert_down_weights[0].len});
+    std.debug.print("\n", .{});
+
+    // Step 4: For now, just show what we would do
+    std.debug.print("🎯 Next steps for full inference:\n", .{});
+    std.debug.print("  1. Load token embeddings from GGUF\n", .{});
