+/// Inference profiler - pprof-like profiler for LLM inference
+/// Automatically detects bottlenecks and suggests fixes
+const std = @import("std");
+
+pub const BottleneckType = enum {
+    gpu_decode, // CRUNCH dominates (>80%) → GPU/memory bottleneck
+    cpu_overhead, // DISPATCH/GATHER high → scheduler overhead
+    speculation, // SPECULATION high → draft model too slow
+    balanced, // No clear bottleneck
+};
+
+pub const ProfilerStats = struct {
+    gather_ns: u64 = 0,
+    crunch_ns: u64 = 0,
+    dispatch_ns: u64 = 0,
+    speculation_ns: u64 = 0,
+    total_ns: u64 = 0,
+    token_count: u64 = 0,
+
+    pub fn reset(self: *ProfilerStats) void {
+        self.* = .{};
+    }
+
+    pub fn detectBottleneck(self: *const ProfilerStats) BottleneckType {
+        if (self.total_ns == 0) return .balanced;
+
+        const crunch_pct = @as(f64, @floatFromInt(self.crunch_ns)) / @as(f64, @floatFromInt(self.total_ns));
+        const dispatch_gather_pct = @as(f64, @floatFromInt(self.dispatch_ns + self.gather_ns)) / @as(f64, @floatFromInt(self.total_ns));
+        const spec_pct = @as(f64, @floatFromInt(self.speculation_ns)) / @as(f64, @floatFromInt(self.total_ns));
+
+        if (crunch_pct > 0.80) return .gpu_decode;
+        if (dispatch_gather_pct > 0.30) return .cpu_overhead;
+        if (spec_pct > 0.40) return .speculation;
+        return .balanced;
+    }
+
+    pub fn print(self: *const ProfilerStats) void {
+        if (self.token_count == 0) return;
+
+        const total_ms = @as(f64, @floatFromInt(self.total_ns)) / 1_000_000.0;
+        const avg_ms_per_token = total_ms / @as(f64, @floatFromInt(self.token_count));
+        const tok_per_sec = 1000.0 / avg_ms_per_token;
+
+        std.debug.print("\n=== Inference Profile ({} tokens, {d:.1f}ms total) ===\n", .{ self.token_count, total_ms });
+        std.debug.print("  Average: {d:.2f}ms/token ({d:.1f} tok/s)\n", .{ avg_ms_per_token, tok_per_sec });
+        std.debug.print("\n  Time Breakdown:\n", .{});
+
+        printPhase("GATHER", self.gather_ns, self.total_ns);
+        printPhase("CRUNCH", self.crunch_ns, self.total_ns);
+        printPhase("DISPATCH", self.dispatch_ns, self.total_ns);
+        printPhase("SPECULATION", self.speculation_ns, self.total_ns);
+
+        const overhead_ns = self.total_ns - (self.gather_ns + self.crunch_ns + self.dispatch_ns + self.speculation_ns);
+        printPhase("OVERHEAD", overhead_ns, self.total_ns);
+
+        // Automatic bottleneck detection
+        const bottleneck = self.detectBottleneck();
+        std.debug.print("\n  🔍 Bottleneck Detected: ", .{});
+        switch (bottleneck) {
+            .gpu_decode => {
+                std.debug.print("GPU/Memory Bound (CRUNCH dominates)\n", .{});
+                std.debug.print("     → Likely cause: Partial GPU offload (CPU ping-pong)\n", .{});
+                std.debug.print("     → Fix: Set n_gpu_layers=99 to offload ALL layers\n", .{});
+                std.debug.print("     → Check logs for: 'offloaded X/Y layers' (want Y/Y)\n", .{});
+            },
+            .cpu_overhead => {
+                std.debug.print("CPU Overhead (GATHER/DISPATCH high)\n", .{});
+                std.debug.print("     → Likely cause: Scheduler/tool/callback overhead\n", .{});
+                std.debug.print("     → Fix: Disable adaptive mode, tools, or hippocampus\n", .{});
+            },
+            .speculation => {
+                std.debug.print("Speculation Overhead (draft model too slow)\n", .{});
+                std.debug.print("     → Likely cause: Draft model not fast enough\n", .{});
+                std.debug.print("     → Fix: Use smaller draft model or disable speculation\n", .{});
+            },
+            .balanced => {
+                std.debug.print("Balanced (no single bottleneck)\n", .{});
+            },
+        }
+
+        std.debug.print("\n", .{});
+    }
+
+    fn printPhase(name: []const u8, phase_ns: u64, total_ns: u64) void {
+        const phase_ms = @as(f64, @floatFromInt(phase_ns)) / 1_000_000.0;
+        const percentage = @as(f64, @floatFromInt(phase_ns)) / @as(f64, @floatFromInt(total_ns)) * 100.0;
+        std.debug.print("    {s:12} {d:6.1f}ms ({d:5.1f}%)\n", .{ name, phase_ms, percentage });
+    }
+};
+
+pub const Profiler = struct {
+    stats: ProfilerStats = .{},
+    phase_start: i64 = 0,
+    step_start: i64 = 0,
+
+    pub fn startStep(self: *Profiler) void {
+        self.step_start = std.time.nanoTimestamp();
+    }
+
+    pub fn endStep(self: *Profiler) void {
+        const now = std.time.nanoTimestamp();
+        const duration: u64 = @intCast(now - self.step_start);
+        self.stats.total_ns += duration;
+        self.stats.token_count += 1;
+    }
+
+    pub fn startPhase(self: *Profiler) void {
+        self.phase_start = std.time.nanoTimestamp();
+    }
+
+    pub fn endGather(self: *Profiler) void {
+        const now = std.time.nanoTimestamp();
+        const duration: u64 = @intCast(now - self.phase_start);
+        self.stats.gather_ns += duration;
+    }
+
+    pub fn endCrunch(self: *Profiler) void {
+        const now = std.time.nanoTimestamp();
+        const duration: u64 = @intCast(now - self.phase_start);
+        self.stats.crunch_ns += duration;
+    }
+
+    pub fn endDispatch(self: *Profiler) void {
+        const now = std.time.nanoTimestamp();
+        const duration: u64 = @intCast(now - self.phase_start);
+        self.stats.dispatch_ns += duration;
+    }
+
+    pub fn endSpeculation(self: *Profiler) void {
+        const now = std.time.nanoTimestamp();
+        const duration: u64 = @intCast(now - self.phase_start);
+        self.stats.speculation_ns += duration;
+    }
+
+    pub fn printStats(self: *const Profiler) void {
+        self.stats.print();
+    }
+};

