+
+    if (args.len < 3) {
+        std.debug.print("Usage: {s} <model.gguf> <prompt>\n", .{args[0]});
+        std.debug.print("\nExample:\n", .{});
+        std.debug.print("  {s} mixtral-8x7b-instruct.gguf \"Hello, how are you?\"\n", .{args[0]});
+        return;
+    }
+
+    const model_path = args[1];
+    const prompt = args[2];
+
+    std.debug.print("\n" ++ "=" ** 60 ++ "\n", .{});
+    std.debug.print("Layer-Split Speculative Decoding Test\n", .{});
+    std.debug.print("=" ** 60 ++ "\n\n", .{});
+
+    std.debug.print("Model: {s}\n", .{model_path});
+    std.debug.print("Prompt: {s}\n\n", .{prompt});
+
+    // Step 1: Load model and get configuration
+    std.debug.print("📦 Step 1: Loading model...\n", .{});
+    var loader = try gguf.GGUFLoader.init(allocator, model_path);
+    defer loader.deinit();
+
+    const config = try loader.loadQwenConfig(allocator);
+    std.debug.print("  ✓ Model loaded: {} layers, {} vocab size\n\n", .{
+        config.n_layers,
+        config.vocab_size,
+    });
+
+    // Step 2: Detect available memory and calculate split
+    std.debug.print("💾 Step 2: Detecting memory and calculating split...\n", .{});
+    const available_memory = try layer_split_mod.getAvailableMemoryGB(allocator);
+
+    const model_info = profile_mod.ModelInfo{
+        .n_layers = config.n_layers,
+        .n_embd = config.hidden_size,
+        .n_vocab = config.vocab_size,
+        .context_length = 2048,
+        .size_gb = 26.5, // TODO: Calculate from file size
+        .n_expert = 0,
+    };
+
+    const split_config = layer_split_mod.calculateOptimalSplit(model_info, available_memory);
+    std.debug.print("\n", .{});
+
+    // Step 3: Initialize Metal engines
+    std.debug.print("🔨 Step 3: Initializing Metal compute engines...\n", .{});
+    var metal = try metal_inf.MetalInferenceEngine.init(allocator, config);
+    defer metal.deinit();
+
+    var bf16_engine = try metal_bf16.MetalBF16MatmulEngine.init(allocator, metal.device, metal.command_queue);
+    defer bf16_engine.deinit();
+
+    std.debug.print("  ✓ Metal engines ready\n\n", .{});
+
+    // Step 4: Initialize streaming engine
+    std.debug.print("📡 Step 4: Initializing SSD streaming engine...\n", .{});
+    var stream_engine = try streaming.StreamingEngine.initWithMode(allocator, &loader, false);
+    defer stream_engine.deinit();
+
+    // Configure streaming engine to skip draft layers (they're in GPU memory)
+    stream_engine.setResidentLayers(split_config.draft_layers);
+
+    std.debug.print("  ✓ Streaming engine ready\n\n", .{});
+
+    // Step 5: Initialize layer-split engine
+    std.debug.print("⚡ Step 5: Initializing layer-split inference engine...\n", .{});
+    var ls_engine = try layer_split_engine.LayerSplitEngine.init(
+        allocator,
+        &loader,
+        metal,
+        bf16_engine,
+        stream_engine,
+        split_config,
+        2048, // n_ctx
+        .fp16, // kv_type
+    );
+    defer ls_engine.deinit();
+
+    std.debug.print("  ✓ Layer-split engine ready\n\n", .{});
+
+    // Step 6: Initialize speculative coordinator
+    std.debug.print("🎯 Step 6: Initializing speculative coordinator...\n", .{});
+    const spec_config = layer_split_spec.LayerSplitSpecConfig{
+        .speculation_depth = 8,
+        .temperature = 0.0, // Greedy
+        .max_tokens = 50,
+        .adaptive_depth = true,
+    };
+
+    var spec = try layer_split_spec.LayerSplitSpeculative.init(
+        allocator,
+        &ls_engine,
+        spec_config,
+    );
+    defer spec.deinit();
+
+    std.debug.print("  ✓ Speculative coordinator ready\n\n", .{});
+
+    // Step 7: Tokenize prompt
+    std.debug.print("🔤 Step 7: Tokenizing prompt...\n", .{});
+
+    // Load llama model for tokenization
+    var llama_model = try llama.Model.load(model_path, .{
+        .n_gpu_layers = 0,
+        .use_mmap = true,
+    });
+    defer llama_model.deinit();
+
+    const vocab = llama_model.getVocab();
+    var prompt_tokens: [512]llama.c.llama_token = undefined;
+    const n_tokens = llama.c.llama_tokenize(
+        vocab,
+        prompt.ptr,
+        @intCast(prompt.len),
+        &prompt_tokens,
+        @intCast(prompt_tokens.len),
+        true,
+        true,
+    );
+
+    if (n_tokens < 0) {
+        std.debug.print("  ✗ Tokenization failed\n", .{});
+        return error.TokenizationFailed;
+    }
+
+    const token_count: usize = @intCast(n_tokens);
+    std.debug.print("  ✓ Tokenized: {} tokens\n\n", .{token_count});
+
+    // Convert to u32 array
+    var prompt_token_ids = try allocator.alloc(u32, token_count);
+    defer allocator.free(prompt_token_ids);
+    for (0..token_count) |i| {
+        prompt_token_ids[i] = @intCast(prompt_tokens[i]);
+    }
+
+    // Step 8: Generate tokens
+    std.debug.print("🚀 Step 8: Starting generation...\n", .{});
+    std.debug.print("=" ** 60 ++ "\n\n", .{});
+
+    // Skip token storage for now (not needed for test)
+
+    // Simple callback that just prints tokens
+    const Callback = struct {
+        fn onToken(token_id: u32) void {
+            std.debug.print("[{}] ", .{token_id});
+        }
+    };
+
+    // Generate
+    try spec.generateFromTokens(prompt_token_ids, &Callback.onToken);
+
+    std.debug.print("\n\n" ++ "=" ** 60 ++ "\n", .{});
+    std.debug.print("Generation complete!\n", .{});
+    std.debug.print("=" ** 60 ++ "\n\n", .{});
+
+    // Step 9: Print statistics
+    std.debug.print("📊 Step 9: Performance statistics\n", .{});
+    spec.printStats();
+
+    std.debug.print("\n✅ Test complete!\n", .{});
+}
